_EXTRA_SOURCE = '"""Build prompt-len-aware smart features for hallucination detection.\n\nCreates:\n    ./artifacts/extra_smart_features_prompt_len/features_dataset_extra_smart_prompt_len.parquet\n    ./artifacts/extra_smart_features_prompt_len/features_test_extra_smart_prompt_len.parquet\n\nThis script intentionally contains only features that require exact prompt/response\nseparation. The only extra input needed versus a hidden-state aggregation pipeline\nis prompt_len. It uses only hidden states, valid masks, and prompt_len.\n"""\n\nfrom __future__ import annotations\n\nimport time\nfrom pathlib import Path\nfrom typing import Dict, Iterable, List\n\nimport numpy as np\nimport pandas as pd\nimport torch\nfrom tqdm import tqdm\n\nfrom model import MAX_LENGTH, get_model_and_tokenizer\n\n\n# ============================================================\n# CONFIG\n# ============================================================\n\nDATA_FILE = "./data/dataset.csv"\nTEST_FILE = "./data/test.csv"\n\nOUTPUT_DIR = Path("./artifacts/extra_smart_features_prompt_len")\nOUTPUT_DIR.mkdir(parents=True, exist_ok=True)\n\nTRAIN_OUTPUT = OUTPUT_DIR / "features_dataset_extra_smart_prompt_len.parquet"\nTEST_OUTPUT = OUTPUT_DIR / "features_test_extra_smart_prompt_len.parquet"\n\nBATCH_SIZE = 2\nEXPORT_TEST = True\n\nLAYERS = [10, 11, 12, 13, 14, 15, 16]\nRICH_LAYERS = [11, 12, 13, 14, 15, 16]\nMIDDLE4_LAYERS = [11, 12, 13, 14]\n\nLAYER_PAIRS = list(zip(LAYERS[:-1], LAYERS[1:]))\nRICH_LAYER_PAIRS = list(zip(RICH_LAYERS[:-1], RICH_LAYERS[1:]))\nLONG_LAYER_PAIRS = [\n    (10, 12),\n    (11, 13),\n    (12, 14),\n    (13, 15),\n    (14, 16),\n    (10, 16),\n    (11, 16),\n]\n\nEPS = 1e-8\n\n\n# ============================================================\n# DEVICE / MODEL\n# ============================================================\n\n\ndef get_device() -> torch.device:\n    if torch.cuda.is_available():\n        return torch.device("cuda")\n    if torch.backends.mps.is_available():\n        return torch.device("mps")\n    return torch.device("cpu")\n\n\n# ============================================================\n# BASIC NUMERIC HELPERS\n# ============================================================\n\n\ndef to_numpy(x) -> np.ndarray:\n    if isinstance(x, torch.Tensor):\n        x = x.detach().cpu().float().numpy()\n    return np.asarray(x, dtype=np.float32)\n\n\ndef clean_value(value) -> float:\n    try:\n        value = float(value)\n    except Exception:\n        return 0.0\n    if not np.isfinite(value):\n        return 0.0\n    return value\n\n\ndef safe_l2(x) -> float:\n    return clean_value(np.linalg.norm(to_numpy(x)))\n\n\ndef safe_cosine(a, b) -> float:\n    a = to_numpy(a)\n    b = to_numpy(b)\n    denom = np.linalg.norm(a) * np.linalg.norm(b) + EPS\n    return clean_value(np.dot(a, b) / denom)\n\n\ndef safe_mean(tokens: torch.Tensor) -> torch.Tensor:\n    if tokens.shape[0] == 0:\n        return torch.zeros(tokens.shape[-1], dtype=tokens.dtype)\n    return tokens.float().mean(dim=0)\n\n\ndef safe_var_mean(tokens: torch.Tensor) -> float:\n    if tokens.shape[0] <= 1:\n        return 0.0\n    return clean_value(tokens.float().var(dim=0, unbiased=False).mean().item())\n\n\ndef entropy(values) -> float:\n    values = np.abs(np.asarray(values, dtype=np.float32))\n    total = float(values.sum())\n    if total <= EPS:\n        return 0.0\n    p = values / total\n    return clean_value(-(p * np.log(p + EPS)).sum())\n\n\ndef add_stats(features: Dict[str, float], prefix: str, values) -> None:\n    values = np.asarray(values, dtype=np.float32)\n    values = np.nan_to_num(values, nan=0.0, posinf=0.0, neginf=0.0)\n    if len(values) == 0:\n        values = np.array([0.0], dtype=np.float32)\n\n    features[f"{prefix}_mean"] = clean_value(values.mean())\n    features[f"{prefix}_std"] = clean_value(values.std())\n    features[f"{prefix}_min"] = clean_value(values.min())\n    features[f"{prefix}_max"] = clean_value(values.max())\n    features[f"{prefix}_range"] = clean_value(values.max() - values.min())\n    features[f"{prefix}_p10"] = clean_value(np.percentile(values, 10))\n    features[f"{prefix}_p25"] = clean_value(np.percentile(values, 25))\n    features[f"{prefix}_p50"] = clean_value(np.percentile(values, 50))\n    features[f"{prefix}_p75"] = clean_value(np.percentile(values, 75))\n    features[f"{prefix}_p90"] = clean_value(np.percentile(values, 90))\n    features[f"{prefix}_iqr"] = clean_value(np.percentile(values, 75) - np.percentile(values, 25))\n    features[f"{prefix}_entropy"] = entropy(values)\n\n\ndef add_trajectory(features: Dict[str, float], prefix: str, values) -> None:\n    values = np.asarray(values, dtype=np.float32)\n    values = np.nan_to_num(values, nan=0.0, posinf=0.0, neginf=0.0)\n    if len(values) == 0:\n        values = np.array([0.0], dtype=np.float32)\n\n    add_stats(features, prefix, values)\n\n    diff1 = np.diff(values) if len(values) >= 2 else np.array([0.0], dtype=np.float32)\n    diff2 = np.diff(values, n=2) if len(values) >= 3 else np.array([0.0], dtype=np.float32)\n\n    x = np.arange(len(values), dtype=np.float32)\n    slope = float(np.polyfit(x, values, 1)[0]) if len(values) >= 2 else 0.0\n\n    early = float(values[:2].mean()) if len(values) >= 2 else float(values.mean())\n    late = float(values[-2:].mean()) if len(values) >= 2 else float(values.mean())\n    roughness = float(np.abs(diff1).sum())\n\n    features[f"{prefix}_slope"] = clean_value(slope)\n    features[f"{prefix}_roughness"] = clean_value(roughness)\n    features[f"{prefix}_smoothness"] = clean_value(1.0 / (1.0 + roughness))\n    features[f"{prefix}_acceleration_mean"] = clean_value(np.abs(diff2).mean())\n    features[f"{prefix}_acceleration_max"] = clean_value(np.abs(diff2).max())\n    features[f"{prefix}_late_minus_early"] = clean_value(late - early)\n    features[f"{prefix}_late_div_early"] = clean_value(late / (abs(early) + EPS))\n    features[f"{prefix}_num_increases"] = clean_value((diff1 > 0).sum())\n    features[f"{prefix}_num_decreases"] = clean_value((diff1 < 0).sum())\n\n    signs = np.sign(diff1)\n    signs = signs[signs != 0]\n    features[f"{prefix}_sign_changes"] = clean_value((signs[1:] != signs[:-1]).sum()) if len(signs) >= 2 else 0.0\n\n\ndef add_spectral(features: Dict[str, float], prefix: str, values) -> None:\n    values = np.asarray(values, dtype=np.float32)\n    values = np.nan_to_num(values, nan=0.0, posinf=0.0, neginf=0.0)\n    if len(values) == 0:\n        values = np.array([0.0], dtype=np.float32)\n\n    centered = values - values.mean()\n    power = np.abs(np.fft.rfft(centered)) ** 2\n    total = float(power.sum())\n    split = max(1, len(power) // 2)\n    low = float(power[:split].sum())\n    high = float(power[split:].sum())\n\n    features[f"{prefix}_fft_energy"] = clean_value(total)\n    features[f"{prefix}_spectral_low_energy"] = clean_value(low)\n    features[f"{prefix}_spectral_high_energy"] = clean_value(high)\n    features[f"{prefix}_spectral_high_low_ratio"] = clean_value(high / (low + EPS))\n    features[f"{prefix}_spectral_entropy"] = entropy(power)\n    features[f"{prefix}_dominant_frequency"] = clean_value(np.argmax(power) / max(len(power) - 1, 1))\n\n\ndef add_vector(features: Dict[str, float], prefix: str, vec: torch.Tensor) -> None:\n    arr = to_numpy(vec)\n    for i, value in enumerate(arr):\n        features[f"{prefix}_d{i}"] = clean_value(value)\n\n\n# ============================================================\n# TOKEN / COVARIANCE HELPERS\n# ============================================================\n\n\ndef pairwise_cosine_stats(tokens: torch.Tensor) -> Dict[str, float]:\n    arr = to_numpy(tokens)\n    if arr.shape[0] <= 1:\n        return {"mean": 1.0, "std": 0.0, "min": 1.0, "p10": 1.0, "p90": 1.0}\n\n    arr = arr / (np.linalg.norm(arr, axis=1, keepdims=True) + EPS)\n    sim = arr @ arr.T\n    tri = sim[np.triu_indices_from(sim, k=1)]\n    return {\n        "mean": clean_value(tri.mean()),\n        "std": clean_value(tri.std()),\n        "min": clean_value(tri.min()),\n        "p10": clean_value(np.percentile(tri, 10)),\n        "p90": clean_value(np.percentile(tri, 90)),\n    }\n\n\ndef covariance_stats(tokens: torch.Tensor) -> Dict[str, float]:\n    arr = to_numpy(tokens)\n    if arr.shape[0] <= 2:\n        return {\n            "trace": 0.0,\n            "top1_ratio": 0.0,\n            "top3_ratio": 0.0,\n            "top5_ratio": 0.0,\n            "effective_rank": 0.0,\n            "participation_ratio": 0.0,\n            "spectral_entropy": 0.0,\n        }\n\n    centered = arr - arr.mean(axis=0, keepdims=True)\n    singular_values = np.linalg.svd(centered, full_matrices=False, compute_uv=False)\n    eig = singular_values ** 2\n    total = float(eig.sum()) + EPS\n    p = eig / total\n    ent = float(-(p * np.log(p + EPS)).sum())\n    return {\n        "trace": clean_value(total),\n        "top1_ratio": clean_value(p[:1].sum()),\n        "top3_ratio": clean_value(p[:3].sum()),\n        "top5_ratio": clean_value(p[:5].sum()),\n        "effective_rank": clean_value(np.exp(ent)),\n        "participation_ratio": clean_value((eig.sum() ** 2) / ((eig ** 2).sum() + EPS)),\n        "spectral_entropy": clean_value(ent),\n    }\n\n\ndef add_zone_token_stats(features: Dict[str, float], prefix: str, tokens: torch.Tensor) -> None:\n    tokens = tokens.float()\n    if tokens.shape[0] == 0:\n        tokens = torch.zeros((1, tokens.shape[-1]), dtype=tokens.dtype)\n\n    norms = torch.linalg.norm(tokens, dim=1).detach().cpu().numpy()\n    add_stats(features, f"{prefix}_token_norm", norms)\n\n    features[f"{prefix}_activation_mean"] = clean_value(tokens.mean().item())\n    features[f"{prefix}_activation_std"] = clean_value(tokens.std(unbiased=False).item()) if tokens.numel() > 1 else 0.0\n    features[f"{prefix}_activation_abs_mean"] = clean_value(tokens.abs().mean().item())\n    features[f"{prefix}_activation_max"] = clean_value(tokens.max().item())\n    features[f"{prefix}_activation_min"] = clean_value(tokens.min().item())\n    features[f"{prefix}_feature_variance_mean"] = safe_var_mean(tokens)\n\n    pcs = pairwise_cosine_stats(tokens)\n    for key, value in pcs.items():\n        features[f"{prefix}_pairwise_cosine_{key}"] = value\n    features[f"{prefix}_disagreement"] = clean_value(1.0 - pcs["mean"])\n\n    cov = covariance_stats(tokens)\n    for key, value in cov.items():\n        features[f"{prefix}_cov_{key}"] = value\n\n\ndef add_response_spectral_tokens(features: Dict[str, float], prefix: str, tokens: torch.Tensor) -> None:\n    """Spectral dynamics over exact response-token positions using hidden states only."""\n    tokens = tokens.float()\n    if tokens.shape[0] == 0:\n        tokens = torch.zeros((1, tokens.shape[-1]), dtype=tokens.dtype)\n\n    token_norms = torch.linalg.norm(tokens, dim=1).detach().cpu().numpy()\n    add_spectral(features, f"{prefix}_token_norm", token_norms)\n\n    centered = to_numpy(tokens - tokens.mean(dim=0, keepdim=True))\n    power = np.abs(np.fft.rfft(centered, axis=0)) ** 2\n    freq_power = power.sum(axis=1)\n    split = max(1, len(freq_power) // 2)\n    low = float(freq_power[:split].sum())\n    high = float(freq_power[split:].sum())\n    total = float(freq_power.sum())\n\n    features[f"{prefix}_hidden_fft_energy"] = clean_value(total)\n    features[f"{prefix}_hidden_fft_low_energy"] = clean_value(low)\n    features[f"{prefix}_hidden_fft_high_energy"] = clean_value(high)\n    features[f"{prefix}_hidden_fft_high_low_ratio"] = clean_value(high / (low + EPS))\n    features[f"{prefix}_hidden_fft_entropy"] = entropy(freq_power)\n    features[f"{prefix}_hidden_fft_dominant_freq"] = clean_value(np.argmax(freq_power) / max(len(freq_power) - 1, 1))\n\n\n# ============================================================\n# PROMPT LENGTH / EXACT ZONES\n# ============================================================\n\n\ndef get_prompt_lengths(tokenizer, prompts: List[str], max_length: int) -> List[int]:\n    lengths = []\n    for prompt in prompts:\n        enc = tokenizer(\n            str(prompt),\n            return_tensors=None,\n            padding=False,\n            truncation=True,\n            max_length=max_length,\n        )\n        lengths.append(len(enc["input_ids"]))\n    return lengths\n\n\ndef split_indices(idx: torch.Tensor) -> Dict[str, torch.Tensor]:\n    n = int(idx.numel())\n    if n == 0:\n        return {\n            "all": idx,\n            "early": idx,\n            "middle": idx,\n            "late": idx,\n            "first_5": idx,\n            "first_10": idx,\n            "last_5": idx,\n            "last_10": idx,\n        }\n\n    third = max(1, n // 3)\n    mid_start = third\n    late_start = min(n, 2 * third)\n    return {\n        "all": idx,\n        "early": idx[:third],\n        "middle": idx[mid_start:late_start] if late_start > mid_start else idx,\n        "late": idx[late_start:] if n > late_start else idx[-third:],\n        "first_5": idx[:min(5, n)],\n        "first_10": idx[:min(10, n)],\n        "last_5": idx[-min(5, n):],\n        "last_10": idx[-min(10, n):],\n    }\n\n\ndef build_prompt_len_zones(hidden: torch.Tensor, valid_mask: torch.Tensor, prompt_len: int):\n    valid_mask = valid_mask.bool().cpu()\n    seq_len = hidden.shape[1]\n    prompt_len = min(max(int(prompt_len), 0), seq_len)\n    pos = torch.arange(seq_len)\n\n    prompt_mask = valid_mask & (pos < prompt_len)\n    response_mask = valid_mask & (pos >= prompt_len)\n\n    # Fallback keeps the feature generator numerically safe for truncated or empty responses.\n    if prompt_mask.sum().item() == 0:\n        prompt_mask = valid_mask.clone()\n    if response_mask.sum().item() == 0:\n        response_mask = valid_mask.clone()\n\n    prompt_idx = torch.where(prompt_mask)[0]\n    response_idx = torch.where(response_mask)[0]\n    all_idx = torch.where(valid_mask)[0]\n\n    zones = {\n        "all": all_idx,\n        "prompt": prompt_idx,\n        "response": response_idx,\n    }\n\n    for name, idx in split_indices(prompt_idx).items():\n        zones[f"prompt_{name}"] = idx\n    for name, idx in split_indices(response_idx).items():\n        zones[f"response_{name}"] = idx\n\n    return zones, prompt_mask, response_mask\n\n\ndef zone_tokens(hidden: torch.Tensor, layer: int, idx: torch.Tensor) -> torch.Tensor:\n    if idx.numel() == 0:\n        return torch.zeros((1, hidden.shape[-1]), dtype=hidden.dtype)\n    return hidden[layer, idx].float()\n\n\ndef build_layer_means(hidden: torch.Tensor, zones: Dict[str, torch.Tensor], zone_names: Iterable[str]):\n    means = {}\n    for zone_name in zone_names:\n        means[zone_name] = {}\n        for layer in LAYERS:\n            means[zone_name][layer] = safe_mean(zone_tokens(hidden, layer, zones[zone_name]))\n    return means\n\n\n# ============================================================\n# FEATURE EXTRACTION FOR ONE SAMPLE\n# ============================================================\n\n\ndef extract_features_one_sample(\n    hidden: torch.Tensor,\n    valid_mask: torch.Tensor,\n    prompt_len: int,\n) -> Dict[str, float]:\n    hidden = hidden.float().cpu()\n    valid_mask = valid_mask.bool().cpu()\n\n    zones, _, _ = build_prompt_len_zones(\n        hidden=hidden,\n        valid_mask=valid_mask,\n        prompt_len=prompt_len,\n    )\n\n    zone_names = [\n        "prompt",\n        "response",\n        "response_early",\n        "response_middle",\n        "response_late",\n        "response_last_5",\n        "response_last_10",\n    ]\n    means = build_layer_means(hidden, zones, zone_names)\n\n    features: Dict[str, float] = {}\n\n    # ========================================================\n    # A. selected_rich_features\n    # ========================================================\n\n    for layer in RICH_LAYERS:\n        add_vector(features, f"pl_rich_response_mean_l{layer}", means["response"][layer])\n        add_vector(\n            features,\n            f"pl_rich_response_minus_prompt_l{layer}",\n            means["response"][layer] - means["prompt"][layer],\n        )\n\n    middle4 = torch.stack([means["response"][layer] for layer in MIDDLE4_LAYERS]).mean(dim=0)\n    add_vector(features, "pl_rich_response_middle4", middle4)\n\n    for left, right in RICH_LAYER_PAIRS:\n        drift = means["response"][right] - means["response"][left]\n        add_vector(features, f"pl_rich_response_drift_l{left}_to_l{right}", drift)\n        add_vector(features, f"pl_rich_abs_response_drift_l{left}_to_l{right}", drift.abs())\n\n    # ========================================================\n    # B. Exact token position dynamics\n    # ========================================================\n\n    exact_zones = [\n        "response",\n        "response_early",\n        "response_middle",\n        "response_late",\n        "response_last_5",\n        "response_last_10",\n    ]\n\n    for zone_name in exact_zones:\n        jumps = []\n        cosines = []\n        drift_norm_means = []\n        drift_norm_stds = []\n        for left, right in LAYER_PAIRS:\n            drift = means[zone_name][right] - means[zone_name][left]\n            jumps.append(safe_l2(drift))\n            cosines.append(safe_cosine(means[zone_name][left], means[zone_name][right]))\n\n            zone_idx = zones[zone_name]\n            token_drift = zone_tokens(hidden, right, zone_idx) - zone_tokens(hidden, left, zone_idx)\n            token_drift_norms = torch.linalg.norm(token_drift.float(), dim=1).detach().cpu().numpy()\n            drift_norm_means.append(float(token_drift_norms.mean()) if len(token_drift_norms) else 0.0)\n            drift_norm_stds.append(float(token_drift_norms.std()) if len(token_drift_norms) else 0.0)\n\n        add_trajectory(features, f"pl_{zone_name}_jump", jumps)\n        add_spectral(features, f"pl_{zone_name}_jump", jumps)\n        add_trajectory(features, f"pl_{zone_name}_layer_cosine", cosines)\n        add_trajectory(features, f"pl_{zone_name}_drift_norm_mean", drift_norm_means)\n        add_trajectory(features, f"pl_{zone_name}_drift_norm_std", drift_norm_stds)\n\n        curvatures = [\n            safe_cosine(\n                means[zone_name][LAYER_PAIRS[i][1]] - means[zone_name][LAYER_PAIRS[i][0]],\n                means[zone_name][LAYER_PAIRS[i + 1][1]] - means[zone_name][LAYER_PAIRS[i + 1][0]],\n            )\n            for i in range(len(LAYER_PAIRS) - 1)\n        ]\n        add_trajectory(features, f"pl_{zone_name}_drift_curvature", curvatures)\n\n    for layer in RICH_LAYERS:\n        early = means["response_early"][layer]\n        middle = means["response_middle"][layer]\n        late = means["response_late"][layer]\n        last5 = means["response_last_5"][layer]\n        last10 = means["response_last_10"][layer]\n        response = means["response"][layer]\n        prompt = means["prompt"][layer]\n\n        pairs = {\n            "late_minus_early": late - early,\n            "middle_minus_early": middle - early,\n            "late_minus_middle": late - middle,\n            "last5_minus_response": last5 - response,\n            "last10_minus_response": last10 - response,\n            "response_minus_prompt": response - prompt,\n            "last5_minus_prompt": last5 - prompt,\n        }\n        for name, vec in pairs.items():\n            add_stats(features, f"pl_pos_l{layer}_{name}", to_numpy(vec))\n\n        features[f"pl_pos_l{layer}_early_late_cosine"] = safe_cosine(early, late)\n        features[f"pl_pos_l{layer}_middle_late_cosine"] = safe_cosine(middle, late)\n        features[f"pl_pos_l{layer}_last5_response_cosine"] = safe_cosine(last5, response)\n        features[f"pl_pos_l{layer}_last10_response_cosine"] = safe_cosine(last10, response)\n        features[f"pl_pos_l{layer}_response_prompt_cosine"] = safe_cosine(response, prompt)\n\n        # Explicit response-ending collapse and exact late instability.\n        last5_tokens = zone_tokens(hidden, layer, zones["response_last_5"])\n        last10_tokens = zone_tokens(hidden, layer, zones["response_last_10"])\n        late_tokens = zone_tokens(hidden, layer, zones["response_late"])\n        response_tokens = zone_tokens(hidden, layer, zones["response"])\n\n        last5_pcs = pairwise_cosine_stats(last5_tokens)\n        last10_pcs = pairwise_cosine_stats(last10_tokens)\n        last5_cov = covariance_stats(last5_tokens)\n        late_pcs = pairwise_cosine_stats(late_tokens)\n\n        features[f"pl_exact_response_ending_collapse_l{layer}_last5_pairwise_cosine"] = last5_pcs["mean"]\n        features[f"pl_exact_response_ending_collapse_l{layer}_last10_pairwise_cosine"] = last10_pcs["mean"]\n        features[f"pl_exact_response_ending_collapse_l{layer}_last5_cov_top1"] = last5_cov["top1_ratio"]\n        features[f"pl_exact_response_ending_collapse_l{layer}_last5_vs_response_disagreement"] = clean_value(\n            abs((1.0 - last5_pcs["mean"]) - (1.0 - pairwise_cosine_stats(response_tokens)["mean"]))\n        )\n        features[f"pl_exact_late_instability_l{layer}"] = clean_value((1.0 - late_pcs["mean"]) + safe_var_mean(late_tokens))\n        features[f"pl_exact_late_stage_semantic_drift_l{layer}"] = safe_l2(last5 - middle)\n\n    response_idx = zones["response"]\n    for left, right in LAYER_PAIRS + LONG_LAYER_PAIRS:\n        drift_tokens = hidden[right, response_idx] - hidden[left, response_idx]\n        if drift_tokens.shape[0] == 0:\n            drift_tokens = torch.zeros((1, hidden.shape[-1]), dtype=hidden.dtype)\n        norms = torch.linalg.norm(drift_tokens.float(), dim=1).detach().cpu().numpy()\n        add_stats(features, f"pl_tokenwise_response_drift_l{left}_to_l{right}", norms)\n        add_trajectory(features, f"pl_tokenwise_response_drift_l{left}_to_l{right}_position", norms)\n        add_spectral(features, f"pl_tokenwise_response_drift_l{left}_to_l{right}_position", norms)\n\n    for zone_name in exact_zones:\n        for layer in RICH_LAYERS:\n            tokens = zone_tokens(hidden, layer, zones[zone_name])\n            add_zone_token_stats(features, f"pl_scalar_{zone_name}_l{layer}", tokens)\n            add_response_spectral_tokens(features, f"pl_spectral_{zone_name}_l{layer}", tokens)\n\n    ending_collapse_series = [\n        features[f"pl_exact_response_ending_collapse_l{layer}_last5_pairwise_cosine"]\n        for layer in RICH_LAYERS\n    ]\n    late_instability_series = [features[f"pl_exact_late_instability_l{layer}"] for layer in RICH_LAYERS]\n    late_stage_semantic_drift_series = [\n        features[f"pl_exact_late_stage_semantic_drift_l{layer}"] for layer in RICH_LAYERS\n    ]\n    add_trajectory(features, "pl_exact_response_ending_collapse_by_layer", ending_collapse_series)\n    add_spectral(features, "pl_exact_response_ending_collapse_by_layer", ending_collapse_series)\n    add_trajectory(features, "pl_exact_late_instability_by_layer", late_instability_series)\n    add_spectral(features, "pl_exact_late_instability_by_layer", late_instability_series)\n    add_trajectory(features, "pl_exact_late_stage_semantic_drift_by_layer", late_stage_semantic_drift_series)\n    add_spectral(features, "pl_exact_late_stage_semantic_drift_by_layer", late_stage_semantic_drift_series)\n\n    # ========================================================\n    # C. Exact self-contradiction\n    # ========================================================\n\n    contradiction_distances = []\n    semantic_divergences = []\n    consistency_cosines = []\n    consistency_decays = []\n    late_stage_drifts = []\n\n    for layer in RICH_LAYERS:\n        early = means["response_early"][layer]\n        middle = means["response_middle"][layer]\n        late = means["response_late"][layer]\n        last5 = means["response_last_5"][layer]\n\n        early_late_dist = safe_l2(late - early)\n        middle_late_dist = safe_l2(late - middle)\n        last5_early_dist = safe_l2(last5 - early)\n        early_late_cos = safe_cosine(early, late)\n        early_middle_cos = safe_cosine(early, middle)\n        middle_late_cos = safe_cosine(middle, late)\n        consistency_decay = early_middle_cos - middle_late_cos\n        semantic_divergence = early_late_dist / (safe_l2(early) + EPS)\n        late_stage_drift = safe_l2(last5 - late)\n\n        features[f"pl_exact_contradiction_l{layer}_early_late_distance"] = early_late_dist\n        features[f"pl_exact_contradiction_l{layer}_middle_late_distance"] = middle_late_dist\n        features[f"pl_exact_contradiction_l{layer}_last5_early_distance"] = last5_early_dist\n        features[f"pl_exact_contradiction_l{layer}_early_late_cosine"] = early_late_cos\n        features[f"pl_exact_contradiction_l{layer}_semantic_divergence"] = semantic_divergence\n        features[f"pl_exact_contradiction_l{layer}_consistency_decay"] = consistency_decay\n        features[f"pl_exact_contradiction_l{layer}_late_stage_semantic_drift"] = late_stage_drift\n\n        contradiction_distances.append(early_late_dist)\n        semantic_divergences.append(semantic_divergence)\n        consistency_cosines.append(early_late_cos)\n        consistency_decays.append(consistency_decay)\n        late_stage_drifts.append(late_stage_drift)\n\n    add_trajectory(features, "pl_exact_contradiction_growth_by_layer", contradiction_distances)\n    add_spectral(features, "pl_exact_contradiction_growth_by_layer", contradiction_distances)\n    add_trajectory(features, "pl_exact_response_semantic_divergence_by_layer", semantic_divergences)\n    add_spectral(features, "pl_exact_response_semantic_divergence_by_layer", semantic_divergences)\n    add_trajectory(features, "pl_exact_response_consistency_by_layer", consistency_cosines)\n    add_trajectory(features, "pl_exact_response_consistency_decay_by_layer", consistency_decays)\n    add_spectral(features, "pl_exact_response_consistency_decay_by_layer", consistency_decays)\n    add_trajectory(features, "pl_exact_late_stage_semantic_drift_contradiction_by_layer", late_stage_drifts)\n    add_spectral(features, "pl_exact_late_stage_semantic_drift_contradiction_by_layer", late_stage_drifts)\n\n    # ========================================================\n    # D. Exact layer localization\n    # ========================================================\n\n    layer_instability = []\n    layer_disagreement = []\n    layer_collapse = []\n    layer_uncertainty_spike = []\n    layer_drift_energy = []\n\n    for layer in RICH_LAYERS:\n        response_tokens = zone_tokens(hidden, layer, zones["response"])\n        pcs = pairwise_cosine_stats(response_tokens)\n        cov = covariance_stats(response_tokens)\n\n        disagreement = clean_value(1.0 - pcs["mean"])\n        collapse = cov["top1_ratio"]\n        instability = clean_value(disagreement + safe_var_mean(response_tokens))\n        uncertainty_spike = clean_value(instability + collapse)\n\n        features[f"pl_layer_l{layer}_response_instability"] = instability\n        features[f"pl_layer_l{layer}_response_disagreement"] = disagreement\n        features[f"pl_layer_l{layer}_response_collapse"] = collapse\n        features[f"pl_layer_l{layer}_response_uncertainty_spike"] = uncertainty_spike\n\n        layer_instability.append(instability)\n        layer_disagreement.append(disagreement)\n        layer_collapse.append(collapse)\n        layer_uncertainty_spike.append(uncertainty_spike)\n\n    for left, right in RICH_LAYER_PAIRS:\n        drift = means["response"][right] - means["response"][left]\n        energy = safe_l2(drift)\n        features[f"pl_layer_transition_l{left}_to_l{right}_response_drift_energy"] = energy\n        layer_drift_energy.append(energy)\n\n    add_trajectory(features, "pl_layer_response_instability", layer_instability)\n    add_spectral(features, "pl_layer_response_instability", layer_instability)\n    add_trajectory(features, "pl_layer_response_disagreement", layer_disagreement)\n    add_spectral(features, "pl_layer_response_disagreement", layer_disagreement)\n    add_trajectory(features, "pl_layer_response_collapse", layer_collapse)\n    add_spectral(features, "pl_layer_response_collapse", layer_collapse)\n    add_trajectory(features, "pl_layer_response_uncertainty_spike", layer_uncertainty_spike)\n    add_spectral(features, "pl_layer_response_uncertainty_spike", layer_uncertainty_spike)\n    add_trajectory(features, "pl_layer_response_drift_localization", layer_drift_energy)\n    add_spectral(features, "pl_layer_response_drift_localization", layer_drift_energy)\n\n    if layer_drift_energy:\n        max_idx = int(np.argmax(layer_drift_energy))\n        features["pl_strongest_response_drift_transition_idx"] = clean_value(max_idx)\n        features["pl_strongest_response_drift_transition_energy"] = clean_value(layer_drift_energy[max_idx])\n\n    return {key: clean_value(value) for key, value in features.items()}\n\n\n# ============================================================\n# DATASET EXTRACTION\n# ============================================================\n\n\ndef extract_dataset_features(df: pd.DataFrame, model, tokenizer, device: torch.device, has_label: bool) -> pd.DataFrame:\n    prompts = df["prompt"].astype(str).tolist()\n    responses = df["response"].astype(str).tolist()\n    texts = [p + r for p, r in zip(prompts, responses)]\n    prompt_lengths = get_prompt_lengths(tokenizer, prompts, MAX_LENGTH)\n\n    rows = []\n\n    for start in tqdm(range(0, len(texts), BATCH_SIZE), desc="Extract prompt-len smart features"):\n        batch_texts = texts[start:start + BATCH_SIZE]\n        batch_prompt_lengths = prompt_lengths[start:start + BATCH_SIZE]\n\n        encoding = tokenizer(\n            batch_texts,\n            return_tensors="pt",\n            padding=True,\n            truncation=True,\n            max_length=MAX_LENGTH,\n        )\n        input_ids = encoding["input_ids"].to(device)\n        attention_mask = encoding["attention_mask"].to(device)\n\n        with torch.no_grad():\n            outputs = model(\n                input_ids=input_ids,\n                attention_mask=attention_mask,\n                output_hidden_states=True,\n            )\n\n        hidden_batch = torch.stack(outputs.hidden_states, dim=1).float().cpu()\n        mask_batch = attention_mask.cpu().bool()\n\n        for i in range(hidden_batch.shape[0]):\n            features = extract_features_one_sample(\n                hidden=hidden_batch[i],\n                valid_mask=mask_batch[i],\n                prompt_len=batch_prompt_lengths[i],\n            )\n            rows.append(features)\n\n        del outputs, hidden_batch, mask_batch\n        if torch.cuda.is_available():\n            torch.cuda.empty_cache()\n\n    out = pd.DataFrame(rows)\n    out.insert(0, "source_index", df.index.to_numpy())\n    if has_label:\n        out["label"] = df["label"].astype(float).astype(int).to_numpy()\n    out["prompt"] = df["prompt"].astype(str).to_numpy()\n    out["response"] = df["response"].astype(str).to_numpy()\n    return out\n\n\n# ============================================================\n# MAIN\n# ============================================================\n\n\ndef main() -> None:\n    t0 = time.time()\n    device = get_device()\n\n    print("=" * 80)\n    print("BUILD EXTRA SMART PROMPT-LEN FEATURES")\n    print("=" * 80)\n    print("Device:", device)\n    print("Output dir:", OUTPUT_DIR)\n    print("Batch size:", BATCH_SIZE)\n    print("Note: hidden states + valid masks + prompt_len only")\n\n    model, tokenizer = get_model_and_tokenizer()\n    if tokenizer.pad_token is None:\n        tokenizer.pad_token = tokenizer.eos_token\n\n    model.to(device)\n    model.eval()\n\n    train_df = pd.read_csv(DATA_FILE)\n    train_features = extract_dataset_features(\n        df=train_df,\n        model=model,\n        tokenizer=tokenizer,\n        device=device,\n        has_label=True,\n    )\n    train_features.to_parquet(TRAIN_OUTPUT, index=False)\n    print("Saved train:", TRAIN_OUTPUT)\n    print("Train shape:", train_features.shape)\n\n    if EXPORT_TEST and Path(TEST_FILE).exists():\n        test_df = pd.read_csv(TEST_FILE)\n        test_features = extract_dataset_features(\n            df=test_df,\n            model=model,\n            tokenizer=tokenizer,\n            device=device,\n            has_label=False,\n        )\n        test_features.to_parquet(TEST_OUTPUT, index=False)\n        print("Saved test:", TEST_OUTPUT)\n        print("Test shape:", test_features.shape)\n\n    print(f"Done in {time.time() - t0:.1f} sec")\n    print("=" * 80)\n\n\nif __name__ == "__main__":\n    main()\n'
_ATTN_SOURCE = '"""\nBuild advanced attention-based features for hallucination detection.\n\nThis script intentionally lives outside the fixed solution.py feature path,\nbecause it requires an additional forward-pass configuration:\n- output_attentions=True\n- eager attention implementation when supported\n\nIt does NOT use logits, generation scores, hooks, external verifiers, or labels.\nThe only boundary signal is prompt length, computed from a prompt_len column when\navailable or by tokenizing the prompt text.\n\nOutputs:\n./artifacts/advanced_features_infrastructure_change/features_dataset_advanced_infrastructure_change.parquet\n./artifacts/advanced_features_infrastructure_change/features_test_advanced_infrastructure_change.parquet\n"""\n\nfrom __future__ import annotations\n\nimport math\nimport os\nimport time\nfrom pathlib import Path\nfrom typing import Dict, Iterable, List, Sequence\n\nimport numpy as np\nimport pandas as pd\nimport torch\nfrom tqdm import tqdm\nfrom transformers import AutoModelForCausalLM, AutoTokenizer\n\ntry:\n    from model import MAX_LENGTH\nexcept Exception:\n    MAX_LENGTH = 512\n\n\n# ============================================================\n# CONFIG\n# ============================================================\n\nMODEL_NAME = os.environ.get("PRIMARY_MODEL_NAME", "Qwen/Qwen2.5-0.5B")\n\nDATA_FILE = "./data/dataset.csv"\nTEST_FILE = "./data/test.csv"\n\nOUTPUT_DIR = Path("./artifacts/advanced_features_infrastructure_change")\nOUTPUT_DIR.mkdir(parents=True, exist_ok=True)\n\nTRAIN_OUTPUT = OUTPUT_DIR / "features_dataset_advanced_infrastructure_change.parquet"\nTEST_OUTPUT = OUTPUT_DIR / "features_test_advanced_infrastructure_change.parquet"\n\nBATCH_SIZE = 1\nEXPORT_TEST = True\nEPS = 1e-8\n\nATTENTION_LAYERS = [11, 12, 13, 14, 15, 16]\n\n\n# ============================================================\n# BASIC HELPERS\n# ============================================================\n\n\ndef get_device() -> torch.device:\n    if torch.cuda.is_available():\n        return torch.device("cuda")\n    if torch.backends.mps.is_available():\n        return torch.device("mps")\n    return torch.device("cpu")\n\n\ndef clean_value(value) -> float:\n    try:\n        value = float(value)\n    except Exception:\n        return 0.0\n    if not np.isfinite(value):\n        return 0.0\n    return value\n\n\ndef add_scalar(features: Dict[str, float], name: str, value) -> None:\n    features[name] = clean_value(value)\n\n\ndef as_np(values) -> np.ndarray:\n    if isinstance(values, torch.Tensor):\n        values = values.detach().cpu().float().numpy()\n    arr = np.asarray(values, dtype=np.float32)\n    return np.nan_to_num(arr, nan=0.0, posinf=0.0, neginf=0.0)\n\n\ndef add_stats(\n    features: Dict[str, float],\n    prefix: str,\n    values: Iterable[float],\n    include_std: bool = True,\n) -> None:\n    arr = as_np(list(values)).reshape(-1)\n    if arr.size == 0:\n        arr = np.array([0.0], dtype=np.float32)\n    add_scalar(features, f"{prefix}_mean", arr.mean())\n    add_scalar(features, f"{prefix}_min", arr.min())\n    add_scalar(features, f"{prefix}_max", arr.max())\n    if include_std:\n        add_scalar(features, f"{prefix}_std", arr.std())\n\n\ndef entropy_rows(prob_matrix: np.ndarray) -> np.ndarray:\n    probs = np.asarray(prob_matrix, dtype=np.float32)\n    probs = np.nan_to_num(probs, nan=0.0, posinf=0.0, neginf=0.0)\n    probs = np.clip(probs, 0.0, 1.0)\n    return -(probs * np.log(probs + EPS)).sum(axis=1)\n\n\ndef slope(values: np.ndarray) -> float:\n    values = as_np(values).reshape(-1)\n    if values.size < 2:\n        return 0.0\n    x = np.arange(values.size, dtype=np.float32)\n    return clean_value(np.polyfit(x, values, 1)[0])\n\n\ndef safe_nonempty_array(values, fallback: float = 0.0) -> np.ndarray:\n    """Return a finite non-empty 1D numpy array.\n\n    Some samples can have an extremely short response span after truncation or\n    EOS stripping. This helper prevents empty-slice warnings and reductions on\n    empty arrays while keeping feature dimensions stable.\n    """\n    arr = as_np(values).reshape(-1)\n    if arr.size == 0:\n        return np.array([fallback], dtype=np.float32)\n    return arr\n\n\ndef safe_segment(values, start: int | None = None, end: int | None = None, fallback: float = 0.0) -> np.ndarray:\n    arr = safe_nonempty_array(values, fallback=fallback)\n    segment = arr[start:end]\n    if segment.size == 0:\n        return np.array([fallback], dtype=np.float32)\n    return segment\n\n\ndef valid_positions(valid_mask: torch.Tensor) -> torch.Tensor:\n    return torch.where(valid_mask.bool().cpu())[0]\n\n\ndef ensure_non_empty(idx: torch.Tensor, fallback: torch.Tensor) -> torch.Tensor:\n    if idx.numel() > 0:\n        return idx\n    if fallback.numel() > 0:\n        return fallback[-1:]\n    return fallback\n\n\ndef last_fraction(idx: torch.Tensor, frac: float) -> torch.Tensor:\n    n = int(idx.numel())\n    if n == 0:\n        return idx\n    keep = max(1, int(round(n * frac)))\n    return idx[-keep:]\n\n\ndef get_prompt_lengths(tokenizer, prompts: Sequence[str], max_length: int) -> List[int]:\n    lengths: List[int] = []\n    for prompt in prompts:\n        enc = tokenizer(\n            str(prompt),\n            return_tensors=None,\n            padding=False,\n            truncation=True,\n            max_length=max_length,\n        )\n        lengths.append(int(len(enc["input_ids"])))\n    return lengths\n\n\ndef get_prompt_len_column_or_tokenize(df: pd.DataFrame, tokenizer) -> List[int]:\n    for candidate in ["prompt_len", "prompt_length", "prompt_len_tokens"]:\n        if candidate in df.columns:\n            return df[candidate].astype(int).tolist()\n    return get_prompt_lengths(tokenizer, df["prompt"].astype(str).tolist(), MAX_LENGTH)\n\n\ndef build_exact_zones(valid_mask: torch.Tensor, prompt_len: int) -> Dict[str, torch.Tensor]:\n    valid_mask = valid_mask.bool().cpu()\n    valid_idx = valid_positions(valid_mask)\n    seq_len = int(valid_mask.numel())\n\n    if valid_idx.numel() == 0:\n        empty = valid_idx\n        return {\n            "all": empty,\n            "prompt": empty,\n            "response": empty,\n            "response_wo_eos": empty,\n            "response_late30": empty,\n            "response_last5": empty,\n            "first_valid": empty,\n        }\n\n    prompt_len = min(max(int(prompt_len), 0), seq_len)\n    pos = torch.arange(seq_len)\n    prompt_idx = torch.where(valid_mask & (pos < prompt_len))[0]\n    response_idx = torch.where(valid_mask & (pos >= prompt_len))[0]\n\n    if response_idx.numel() == 0:\n        response_idx = valid_idx[-1:]\n    if prompt_idx.numel() == 0:\n        prompt_idx = valid_idx[:1]\n\n    response_wo_eos = response_idx[:-1] if response_idx.numel() >= 2 else response_idx.new_empty((0,))\n    if response_wo_eos.numel() == 0:\n        response_wo_eos = response_idx\n\n    return {\n        "all": valid_idx,\n        "prompt": ensure_non_empty(prompt_idx, valid_idx),\n        "response": ensure_non_empty(response_idx, valid_idx),\n        "response_wo_eos": ensure_non_empty(response_wo_eos, response_idx),\n        "response_late30": ensure_non_empty(last_fraction(response_idx, 0.30), response_idx),\n        "response_last5": ensure_non_empty(response_idx[-min(5, int(response_idx.numel())):], response_idx),\n        "first_valid": valid_idx[:1],\n    }\n\n\ndef safe_layer_index(layer: int, n_layers: int) -> int:\n    if layer < 0:\n        layer = n_layers + layer\n    return int(min(max(layer, 0), n_layers - 1))\n\n\n# ============================================================\n# MODEL LOADING\n# ============================================================\n\n\ndef load_attention_model_and_tokenizer(device: torch.device):\n    print(f"[Model] Loading \'{MODEL_NAME}\' with attention outputs enabled ...")\n    tokenizer = AutoTokenizer.from_pretrained(MODEL_NAME)\n    if tokenizer.pad_token is None:\n        tokenizer.pad_token = tokenizer.eos_token\n\n    kwargs = {\n        "output_hidden_states": False,\n        "output_attentions": True,\n        "torch_dtype": torch.bfloat16,\n    }\n    # Some attention implementations do not return attention weights. For Qwen,\n    # eager attention is the safest option when available.\n    try:\n        model = AutoModelForCausalLM.from_pretrained(\n            MODEL_NAME,\n            attn_implementation="eager",\n            **kwargs,\n        )\n    except TypeError:\n        model = AutoModelForCausalLM.from_pretrained(MODEL_NAME, **kwargs)\n\n    model.to(device)\n    model.eval()\n    return model, tokenizer\n\n\n# ============================================================\n# ATTENTION FEATURES\n# ============================================================\n\n\ndef attention_masses_for_head(\n    head_attn: np.ndarray,\n    query_idx: np.ndarray,\n    prompt_idx: np.ndarray,\n    response_idx: np.ndarray,\n    first_valid_idx: int,\n    valid_idx: np.ndarray,\n) -> Dict[str, np.ndarray]:\n    """Compute prompt/response/sink masses for one attention head.\n\n    head_attn shape is [seq_len, seq_len]. Rows are query positions, columns are\n    key positions.\n    """\n    if query_idx.size == 0:\n        query_idx = response_idx[-1:] if response_idx.size else valid_idx[-1:]\n    if prompt_idx.size == 0:\n        prompt_idx = valid_idx[:1]\n    if response_idx.size == 0:\n        response_idx = valid_idx[-1:]\n\n    q_attn = head_attn[query_idx]\n    prompt_mass = q_attn[:, prompt_idx].sum(axis=1)\n    response_mass = q_attn[:, response_idx].sum(axis=1)\n    sink_mass = q_attn[:, first_valid_idx]\n    valid_probs = q_attn[:, valid_idx]\n    entropy = entropy_rows(valid_probs)\n    lookback = prompt_mass / (prompt_mass + response_mass + EPS)\n\n    return {\n        "prompt_mass": prompt_mass,\n        "response_mass": response_mass,\n        "sink_mass": sink_mass,\n        "entropy": entropy,\n        "lookback": lookback,\n    }\n\n\ndef add_layer_head_attention_features(\n    features: Dict[str, float],\n    layer_idx: int,\n    attn_layer: torch.Tensor,\n    zones: Dict[str, torch.Tensor],\n) -> None:\n    """Add per-layer/head attention features and layer summaries."""\n    attn_np = as_np(attn_layer)  # [heads, seq, seq]\n    n_heads = int(attn_np.shape[0])\n\n    valid_idx = zones["all"].numpy().astype(int)\n    prompt_idx = zones["prompt"].numpy().astype(int)\n    response_idx = zones["response"].numpy().astype(int)\n    response_query_idx = zones["response_wo_eos"].numpy().astype(int)\n    first_valid_idx = int(zones["first_valid"][0].item()) if zones["first_valid"].numel() else 0\n\n    head_lookback_means = []\n    head_entropy_means = []\n    layer_prompt_masses = []\n    layer_response_masses = []\n    layer_sink_masses = []\n\n    for head_idx in range(n_heads):\n        masses = attention_masses_for_head(\n            head_attn=attn_np[head_idx],\n            query_idx=response_query_idx,\n            prompt_idx=prompt_idx,\n            response_idx=response_idx,\n            first_valid_idx=first_valid_idx,\n            valid_idx=valid_idx,\n        )\n\n        prefix = f"attn_l{layer_idx}_h{head_idx}"\n\n        # 1. Attention Lookback-Lens per layer/head.\n        add_stats(features, f"{prefix}_lookback", masses["lookback"], include_std=True)\n        add_stats(features, f"{prefix}_attention_entropy", masses["entropy"], include_std=True)\n        add_scalar(features, f"{prefix}_attention_to_sink_mean", masses["sink_mass"].mean())\n        add_scalar(features, f"{prefix}_attention_to_sink_max", masses["sink_mass"].max())\n        add_scalar(features, f"{prefix}_attention_to_response_mean", masses["response_mass"].mean())\n        add_scalar(features, f"{prefix}_attention_to_response_max", masses["response_mass"].max())\n\n        # 2. Attention trajectory / grounding decay over response positions.\n        lookback_by_pos = safe_nonempty_array(masses["lookback"], fallback=0.0)\n        late_start = min(len(lookback_by_pos) - 1, max(0, int(round(len(lookback_by_pos) * 0.70))))\n        late_vals = safe_segment(lookback_by_pos, late_start, None, fallback=lookback_by_pos[-1])\n        first_end = max(1, min(5, len(lookback_by_pos)))\n        first_vals = safe_segment(lookback_by_pos, 0, first_end, fallback=lookback_by_pos[0])\n        last5_vals = safe_segment(lookback_by_pos, -min(5, len(lookback_by_pos)), None, fallback=lookback_by_pos[-1])\n        diffs = np.diff(lookback_by_pos) if lookback_by_pos.size >= 2 else np.array([0.0], dtype=np.float32)\n\n        lookback_mean = float(lookback_by_pos.mean())\n        late_mean = float(late_vals.mean())\n        first_mean = float(first_vals.mean())\n        last5_mean = float(last5_vals.mean())\n\n        add_scalar(features, f"{prefix}_grounding_slope", slope(lookback_by_pos))\n        add_scalar(features, f"{prefix}_grounding_late_minus_early", late_mean - first_mean)\n        add_scalar(features, f"{prefix}_grounding_decay_ratio", late_mean / (first_mean + EPS))\n        add_scalar(features, f"{prefix}_grounding_roughness", np.abs(diffs).sum())\n        add_scalar(features, f"{prefix}_grounding_min_late", late_vals.min())\n        add_scalar(features, f"{prefix}_grounding_last5_mean", last5_mean)\n        add_scalar(features, f"{prefix}_grounding_last5_vs_all", last5_mean / (lookback_mean + EPS))\n\n        head_lookback_means.append(clean_value(masses["lookback"].mean()))\n        head_entropy_means.append(clean_value(masses["entropy"].mean()))\n        layer_prompt_masses.extend(as_np(masses["prompt_mass"]).tolist())\n        layer_response_masses.extend(as_np(masses["response_mass"]).tolist())\n        layer_sink_masses.extend(as_np(masses["sink_mass"]).tolist())\n\n    # 3. Head disagreement per layer.\n    head_lookback_values = as_np(head_lookback_means)\n    head_entropy_values = as_np(head_entropy_means)\n    add_scalar(features, f"attn_l{layer_idx}_head_lookback_mean", head_lookback_values.mean())\n    add_scalar(features, f"attn_l{layer_idx}_head_lookback_std", head_lookback_values.std())\n    add_scalar(features, f"attn_l{layer_idx}_head_lookback_min", head_lookback_values.min())\n    add_scalar(features, f"attn_l{layer_idx}_head_lookback_max", head_lookback_values.max())\n    add_scalar(features, f"attn_l{layer_idx}_head_disagreement", head_lookback_values.std())\n    add_scalar(features, f"attn_l{layer_idx}_head_collapse", head_lookback_values.max() - head_lookback_values.mean())\n    add_scalar(features, f"attn_l{layer_idx}_head_entropy_mean", head_entropy_values.mean())\n\n    # 4. Prompt / response / sink mass summaries per layer.\n    add_stats(features, f"attn_l{layer_idx}_prompt_mass_layer", layer_prompt_masses, include_std=True)\n    add_stats(features, f"attn_l{layer_idx}_response_mass_layer", layer_response_masses, include_std=True)\n    sink_arr = as_np(layer_sink_masses)\n    add_scalar(features, f"attn_l{layer_idx}_sink_mass_layer_mean", sink_arr.mean())\n    add_scalar(features, f"attn_l{layer_idx}_sink_mass_layer_std", sink_arr.std())\n    add_scalar(features, f"attn_l{layer_idx}_sink_mass_layer_max", sink_arr.max())\n\n\ndef add_attention_features(\n    features: Dict[str, float],\n    attentions: Sequence[torch.Tensor],\n    zones: Dict[str, torch.Tensor],\n) -> None:\n    layer_level_lookback = []\n    layer_level_prompt_mass = []\n    layer_level_response_mass = []\n    layer_level_sink_mass = []\n\n    for requested_layer in ATTENTION_LAYERS:\n        attn_pos = safe_layer_index(requested_layer, len(attentions))\n        # attentions[attn_pos] shape for one sample: [heads, seq, seq]\n        attn_layer = attentions[attn_pos]\n        add_layer_head_attention_features(features, requested_layer, attn_layer, zones)\n\n        layer_level_lookback.append(features.get(f"attn_l{requested_layer}_head_lookback_mean", 0.0))\n        layer_level_prompt_mass.append(features.get(f"attn_l{requested_layer}_prompt_mass_layer_mean", 0.0))\n        layer_level_response_mass.append(features.get(f"attn_l{requested_layer}_response_mass_layer_mean", 0.0))\n        layer_level_sink_mass.append(features.get(f"attn_l{requested_layer}_sink_mass_layer_mean", 0.0))\n\n    add_stats(features, "attn_l11_l16_layer_lookback", layer_level_lookback, include_std=True)\n    add_scalar(features, "attn_l11_l16_layer_lookback_slope", slope(as_np(layer_level_lookback)))\n    add_scalar(\n        features,\n        "attn_l11_l16_layer_lookback_late_minus_early",\n        np.mean(layer_level_lookback[-2:]) - np.mean(layer_level_lookback[:2]),\n    )\n\n    add_stats(features, "attn_l11_l16_prompt_mass", layer_level_prompt_mass, include_std=True)\n    add_stats(features, "attn_l11_l16_response_mass", layer_level_response_mass, include_std=True)\n    add_stats(features, "attn_l11_l16_sink_mass", layer_level_sink_mass, include_std=True)\n\n\ndef add_length_meta_features(\n    features: Dict[str, float],\n    zones: Dict[str, torch.Tensor],\n    prompt_len: int,\n) -> None:\n    n_valid = int(zones["all"].numel())\n    prompt_tokens = int(zones["prompt"].numel())\n    response_tokens = int(zones["response"].numel())\n    response_wo_eos_tokens = int(zones["response_wo_eos"].numel())\n\n    add_scalar(features, "n_valid", n_valid)\n    add_scalar(features, "prompt_len_tokens", prompt_tokens)\n    add_scalar(features, "raw_prompt_len_tokens", int(prompt_len))\n    add_scalar(features, "response_len_tokens", response_tokens)\n    add_scalar(features, "response_wo_eos_len", response_wo_eos_tokens)\n    add_scalar(features, "response_fraction", response_tokens / (n_valid + EPS))\n    add_scalar(features, "log1p_prompt_len", math.log1p(prompt_tokens))\n    add_scalar(features, "log1p_response_len", math.log1p(response_tokens))\n    add_scalar(features, "is_response_short", int(response_tokens <= 2))\n    add_scalar(features, "is_maybe_truncated", int(n_valid >= MAX_LENGTH - 2))\n\n\n# ============================================================\n# SAMPLE AND DATASET EXTRACTION\n# ============================================================\n\n\ndef extract_features_one_sample(\n    attentions: Sequence[torch.Tensor],\n    valid_mask: torch.Tensor,\n    prompt_len: int,\n) -> Dict[str, float]:\n    valid_mask = valid_mask.bool().cpu()\n    zones = build_exact_zones(valid_mask, prompt_len)\n\n    features: Dict[str, float] = {}\n    add_length_meta_features(features, zones, prompt_len)\n    add_attention_features(features, attentions, zones)\n    return {key: clean_value(value) for key, value in features.items()}\n\n\ndef extract_dataset_features(\n    df: pd.DataFrame,\n    model,\n    tokenizer,\n    device: torch.device,\n    has_label: bool,\n) -> pd.DataFrame:\n    prompts = df["prompt"].astype(str).tolist()\n    responses = df["response"].astype(str).tolist()\n    prompt_lengths = get_prompt_len_column_or_tokenize(df, tokenizer)\n    texts = [p + r for p, r in zip(prompts, responses)]\n\n    rows: List[Dict[str, float]] = []\n\n    for start in tqdm(range(0, len(texts), BATCH_SIZE), desc="Extract attention features"):\n        batch_texts = texts[start:start + BATCH_SIZE]\n        batch_prompt_lengths = prompt_lengths[start:start + BATCH_SIZE]\n\n        encoding = tokenizer(\n            batch_texts,\n            return_tensors="pt",\n            padding=True,\n            truncation=True,\n            max_length=MAX_LENGTH,\n        )\n        input_ids = encoding["input_ids"].to(device)\n        attention_mask = encoding["attention_mask"].to(device)\n\n        with torch.no_grad():\n            outputs = model(\n                input_ids=input_ids,\n                attention_mask=attention_mask,\n                output_attentions=True,\n                output_hidden_states=False,\n                use_cache=False,\n            )\n\n        if outputs.attentions is None:\n            raise RuntimeError(\n                "Model did not return attentions. Try using an eager attention implementation."\n            )\n\n        mask_batch = attention_mask.detach().cpu().bool()\n        # Convert from tuple[layer][batch, head, seq, seq] to per-sample tuple.\n        attentions_cpu = [att.detach().cpu().float() for att in outputs.attentions]\n\n        for i in range(input_ids.shape[0]):\n            sample_attentions = [att[i] for att in attentions_cpu]\n            rows.append(\n                extract_features_one_sample(\n                    attentions=sample_attentions,\n                    valid_mask=mask_batch[i],\n                    prompt_len=batch_prompt_lengths[i],\n                )\n            )\n\n        del outputs, attentions_cpu, mask_batch, input_ids, attention_mask, encoding\n        if torch.cuda.is_available():\n            torch.cuda.empty_cache()\n\n    out = pd.DataFrame(rows)\n    out = out.replace([np.inf, -np.inf], 0.0).fillna(0.0)\n    out.insert(0, "source_index", df.index.to_numpy())\n\n    if has_label:\n        out["label"] = df["label"].astype(float).astype(int).to_numpy()\n\n    out["prompt"] = df["prompt"].astype(str).to_numpy()\n    out["response"] = df["response"].astype(str).to_numpy()\n    return out\n\n\n# ============================================================\n# MAIN\n# ============================================================\n\n\ndef main() -> None:\n    t0 = time.time()\n    device = get_device()\n\n    print("=" * 80)\n    print("BUILD ADVANCED ATTENTION-BASED FEATURES")\n    print("=" * 80)\n    print(f"Device      : {device}")\n    print(f"Model       : {MODEL_NAME}")\n    print(f"Data file   : {DATA_FILE}")\n    print(f"Test file   : {TEST_FILE}")\n    print(f"Output dir  : {OUTPUT_DIR}")\n    print(f"Batch size  : {BATCH_SIZE}")\n    print("Note        : uses attentions; no logits, hooks, or external verifier")\n\n    model, tokenizer = load_attention_model_and_tokenizer(device)\n\n    train_df = pd.read_csv(DATA_FILE)\n    print(f"\\nDataset rows: {len(train_df)}")\n    train_features = extract_dataset_features(\n        df=train_df,\n        model=model,\n        tokenizer=tokenizer,\n        device=device,\n        has_label=True,\n    )\n    train_features.to_parquet(TRAIN_OUTPUT, index=False)\n    print(f"Saved train: {TRAIN_OUTPUT}")\n    print(f"Train shape: {train_features.shape}")\n\n    if EXPORT_TEST and Path(TEST_FILE).exists():\n        test_df = pd.read_csv(TEST_FILE)\n        print(f"\\nTest rows: {len(test_df)}")\n        test_features = extract_dataset_features(\n            df=test_df,\n            model=model,\n            tokenizer=tokenizer,\n            device=device,\n            has_label=False,\n        )\n        test_features.to_parquet(TEST_OUTPUT, index=False)\n        print(f"Saved test: {TEST_OUTPUT}")\n        print(f"Test shape: {test_features.shape}")\n\n    print(f"\\nDone in {time.time() - t0:.1f} sec")\n    print("=" * 80)\n\n\nif __name__ == "__main__":\n    main()\n'
_ADV_SOURCE = '"""\nBuild advanced prompt-length-aware hidden-state features.\n\nThis script uses only one additional boundary signal: prompt_len.\nIt does NOT require output_attentions, logits, hooks, or any external model.\n\nOutputs:\n./artifacts/advanced_features_prompt_len/features_dataset_advanced_prompt_len.parquet\n./artifacts/advanced_features_prompt_len/features_test_advanced_prompt_len.parquet\n"""\n\nfrom __future__ import annotations\n\nimport math\nimport time\nfrom pathlib import Path\nfrom typing import Dict, Iterable, List, Sequence, Tuple\n\nimport numpy as np\nimport pandas as pd\nimport torch\nfrom tqdm import tqdm\n\nfrom model import MAX_LENGTH, get_model_and_tokenizer\n\n\n# ============================================================\n# CONFIG\n# ============================================================\n\nDATA_FILE = "./data/dataset.csv"\nTEST_FILE = "./data/test.csv"\n\nOUTPUT_DIR = Path("./artifacts/advanced_features_prompt_len")\nOUTPUT_DIR.mkdir(parents=True, exist_ok=True)\n\nTRAIN_OUTPUT = OUTPUT_DIR / "features_dataset_advanced_prompt_len.parquet"\nTEST_OUTPUT = OUTPUT_DIR / "features_test_advanced_prompt_len.parquet"\n\nBATCH_SIZE = 1\nEXPORT_TEST = True\nEPS = 1e-8\n\nMAX_POOL_LAYERS = [12, 13, 16]\nMEAN_POOL_LAYERS = [14, 15, 16]\nCOMPACT_LAYERS = list(range(10, 20))\nTEMPORAL_LAYERS = [12, 13, 14, 15, 16]\nICR_LAYERS = [0, 6, 12, 18, 23]\nCENTROID_LAYERS = [1, 6, 12, 18, 23]\n\n\n# ============================================================\n# BASIC HELPERS\n# ============================================================\n\n\ndef get_device() -> torch.device:\n    if torch.cuda.is_available():\n        return torch.device("cuda")\n    if torch.backends.mps.is_available():\n        return torch.device("mps")\n    return torch.device("cpu")\n\n\ndef clean_value(value) -> float:\n    try:\n        value = float(value)\n    except Exception:\n        return 0.0\n    if not np.isfinite(value):\n        return 0.0\n    return value\n\n\ndef to_numpy(x) -> np.ndarray:\n    if isinstance(x, torch.Tensor):\n        x = x.detach().cpu().float().numpy()\n    return np.asarray(x, dtype=np.float32)\n\n\ndef safe_layer_index(layer: int, n_layers: int) -> int:\n    if layer < 0:\n        layer = n_layers + layer\n    return int(min(max(layer, 0), n_layers - 1))\n\n\ndef safe_l2(x) -> float:\n    arr = to_numpy(x).reshape(-1)\n    return clean_value(np.linalg.norm(arr))\n\n\ndef safe_cosine(a, b) -> float:\n    a_arr = to_numpy(a).reshape(-1)\n    b_arr = to_numpy(b).reshape(-1)\n    denom = np.linalg.norm(a_arr) * np.linalg.norm(b_arr) + EPS\n    return clean_value(np.dot(a_arr, b_arr) / denom)\n\n\ndef safe_angle(a, b) -> float:\n    cos = np.clip(safe_cosine(a, b), -1.0, 1.0)\n    return clean_value(math.acos(cos))\n\n\ndef safe_mean(tokens: torch.Tensor) -> torch.Tensor:\n    if tokens.numel() == 0 or tokens.shape[0] == 0:\n        return torch.zeros(tokens.shape[-1], dtype=torch.float32)\n    return tokens.float().mean(dim=0)\n\n\ndef safe_max(tokens: torch.Tensor) -> torch.Tensor:\n    if tokens.numel() == 0 or tokens.shape[0] == 0:\n        return torch.zeros(tokens.shape[-1], dtype=torch.float32)\n    return tokens.float().max(dim=0).values\n\n\ndef add_scalar(features: Dict[str, float], name: str, value) -> None:\n    features[name] = clean_value(value)\n\n\ndef add_vector(features: Dict[str, float], prefix: str, vector: torch.Tensor | np.ndarray) -> None:\n    arr = to_numpy(vector).reshape(-1)\n    arr = np.nan_to_num(arr, nan=0.0, posinf=0.0, neginf=0.0)\n    for dim, value in enumerate(arr):\n        features[f"{prefix}_d{dim}"] = clean_value(value)\n\n\ndef add_basic_stats(features: Dict[str, float], prefix: str, values: Iterable[float]) -> None:\n    arr = np.asarray(list(values), dtype=np.float32)\n    arr = np.nan_to_num(arr, nan=0.0, posinf=0.0, neginf=0.0)\n    if arr.size == 0:\n        arr = np.array([0.0], dtype=np.float32)\n    add_scalar(features, f"{prefix}_mean", arr.mean())\n    add_scalar(features, f"{prefix}_std", arr.std())\n    add_scalar(features, f"{prefix}_min", arr.min())\n    add_scalar(features, f"{prefix}_max", arr.max())\n\n\ndef valid_positions(valid_mask: torch.Tensor) -> torch.Tensor:\n    return torch.where(valid_mask.bool().cpu())[0]\n\n\ndef ensure_non_empty(idx: torch.Tensor, fallback: torch.Tensor) -> torch.Tensor:\n    if idx.numel() > 0:\n        return idx\n    if fallback.numel() > 0:\n        return fallback[-1:]\n    return fallback\n\n\ndef first_fraction(idx: torch.Tensor, frac: float) -> torch.Tensor:\n    n = int(idx.numel())\n    if n == 0:\n        return idx\n    keep = max(1, int(round(n * frac)))\n    return idx[:keep]\n\n\ndef middle_fraction(idx: torch.Tensor, start_frac: float, end_frac: float) -> torch.Tensor:\n    n = int(idx.numel())\n    if n == 0:\n        return idx\n    start = min(n - 1, max(0, int(round(n * start_frac))))\n    end = min(n, max(start + 1, int(round(n * end_frac))))\n    return idx[start:end]\n\n\ndef last_fraction(idx: torch.Tensor, frac: float) -> torch.Tensor:\n    n = int(idx.numel())\n    if n == 0:\n        return idx\n    keep = max(1, int(round(n * frac)))\n    return idx[-keep:]\n\n\ndef get_prompt_lengths(tokenizer, prompts: Sequence[str], max_length: int) -> List[int]:\n    lengths = []\n    for prompt in prompts:\n        enc = tokenizer(\n            str(prompt),\n            return_tensors=None,\n            padding=False,\n            truncation=True,\n            max_length=max_length,\n        )\n        lengths.append(int(len(enc["input_ids"])))\n    return lengths\n\n\ndef get_prompt_len_column_or_tokenize(df: pd.DataFrame, tokenizer) -> List[int]:\n    for candidate in ["prompt_len", "prompt_length", "prompt_len_tokens"]:\n        if candidate in df.columns:\n            return df[candidate].astype(int).tolist()\n    return get_prompt_lengths(tokenizer, df["prompt"].astype(str).tolist(), MAX_LENGTH)\n\n\ndef build_exact_zones(valid_mask: torch.Tensor, prompt_len: int) -> Dict[str, torch.Tensor]:\n    valid_mask = valid_mask.bool().cpu()\n    valid_idx = valid_positions(valid_mask)\n    seq_len = int(valid_mask.numel())\n\n    if valid_idx.numel() == 0:\n        empty = valid_idx\n        return {\n            "all": empty,\n            "prompt": empty,\n            "response": empty,\n            "response_wo_eos": empty,\n            "response_first30": empty,\n            "response_middle40": empty,\n            "response_late30": empty,\n            "response_last5": empty,\n            "response_last10": empty,\n            "prompt_last5": empty,\n            "prompt_last10": empty,\n            "last_token": empty,\n        }\n\n    prompt_len = min(max(int(prompt_len), 0), seq_len)\n    pos = torch.arange(seq_len)\n\n    prompt_idx = torch.where(valid_mask & (pos < prompt_len))[0]\n    response_idx = torch.where(valid_mask & (pos >= prompt_len))[0]\n\n    # Fallbacks requested in the spec.\n    if response_idx.numel() == 0:\n        response_idx = valid_idx[-1:]\n    if prompt_idx.numel() == 0:\n        prompt_idx = valid_idx[: max(1, min(int(prompt_len), int(valid_idx.numel())))]\n        prompt_idx = ensure_non_empty(prompt_idx, valid_idx)\n\n    response_wo_eos = response_idx[:-1] if response_idx.numel() >= 2 else response_idx.new_empty((0,))\n    if response_wo_eos.numel() == 0:\n        response_wo_eos = response_idx\n\n    zones = {\n        "all": valid_idx,\n        "prompt": ensure_non_empty(prompt_idx, valid_idx),\n        "response": ensure_non_empty(response_idx, valid_idx),\n        "response_wo_eos": ensure_non_empty(response_wo_eos, response_idx),\n        "response_first30": ensure_non_empty(first_fraction(response_idx, 0.30), response_idx),\n        "response_middle40": ensure_non_empty(middle_fraction(response_idx, 0.30, 0.70), response_idx),\n        "response_late30": ensure_non_empty(last_fraction(response_idx, 0.30), response_idx),\n        "response_last5": ensure_non_empty(response_idx[-min(5, int(response_idx.numel())):], response_idx),\n        "response_last10": ensure_non_empty(response_idx[-min(10, int(response_idx.numel())):], response_idx),\n        "prompt_last5": ensure_non_empty(prompt_idx[-min(5, int(prompt_idx.numel())):], prompt_idx),\n        "prompt_last10": ensure_non_empty(prompt_idx[-min(10, int(prompt_idx.numel())):], prompt_idx),\n        "last_token": valid_idx[-1:],\n    }\n    return zones\n\n\ndef zone_tokens(hidden: torch.Tensor, layer: int, idx: torch.Tensor) -> torch.Tensor:\n    layer_idx = safe_layer_index(layer, hidden.shape[0])\n    if idx.numel() == 0:\n        return torch.zeros((1, hidden.shape[-1]), dtype=torch.float32)\n    return hidden[layer_idx, idx].float().cpu()\n\n\ndef layer_vector(hidden: torch.Tensor, layer: int, pos: int) -> torch.Tensor:\n    layer_idx = safe_layer_index(layer, hidden.shape[0])\n    return hidden[layer_idx, pos].float().cpu()\n\n\n# ============================================================\n# 1. EXACT RESPONSE MASKS + 10. LENGTH/META FEATURES\n# ============================================================\n\n\ndef add_length_meta_features(\n    features: Dict[str, float],\n    zones: Dict[str, torch.Tensor],\n    prompt_len: int,\n    max_length: int,\n) -> None:\n    n_valid = int(zones["all"].numel())\n    prompt_tokens = int(zones["prompt"].numel())\n    response_tokens = int(zones["response"].numel())\n    response_wo_eos_tokens = int(zones["response_wo_eos"].numel())\n\n    add_scalar(features, "n_valid", n_valid)\n    add_scalar(features, "prompt_len_tokens", prompt_tokens)\n    add_scalar(features, "raw_prompt_len_tokens", int(prompt_len))\n    add_scalar(features, "response_len_tokens", response_tokens)\n    add_scalar(features, "response_wo_eos_len", response_wo_eos_tokens)\n    add_scalar(features, "log1p_prompt_len", np.log1p(prompt_tokens))\n    add_scalar(features, "log1p_response_len", np.log1p(response_tokens))\n    add_scalar(features, "response_len_div_n_valid", response_tokens / (n_valid + EPS))\n    add_scalar(features, "response_len_div_prompt_len", response_tokens / (prompt_tokens + EPS))\n    add_scalar(features, "response_len_div_512", response_tokens / 512.0)\n    add_scalar(features, "is_response_short", int(response_tokens <= 2))\n    add_scalar(\n        features,\n        "is_response_truncated_or_empty",\n        int(response_tokens <= 1 or n_valid >= max_length - 2),\n    )\n\n\n# ============================================================\n# 2-3. EXACT MAX/MEAN + L16 HYBRID\n# ============================================================\n\n\ndef add_exact_pooling_features(\n    features: Dict[str, float],\n    hidden: torch.Tensor,\n    zones: Dict[str, torch.Tensor],\n) -> None:\n    for layer in MAX_POOL_LAYERS:\n        vec = safe_max(zone_tokens(hidden, layer, zones["response_wo_eos"]))\n        add_vector(features, f"max_l{layer}_response_wo_eos", vec)\n\n    for layer in MEAN_POOL_LAYERS:\n        vec = safe_mean(zone_tokens(hidden, layer, zones["response_wo_eos"]))\n        add_vector(features, f"mean_l{layer}_response_wo_eos", vec)\n\n    # Ablation variants without EOS stripping.\n    for layer in [12, 13]:\n        add_vector(features, f"max_l{layer}_response", safe_max(zone_tokens(hidden, layer, zones["response"])))\n    for layer in [14, 15]:\n        add_vector(features, f"mean_l{layer}_response", safe_mean(zone_tokens(hidden, layer, zones["response"])))\n\n    # Exact layer-16 hybrid block.\n    add_vector(features, "l16_response_max", safe_max(zone_tokens(hidden, 16, zones["response"])))\n    add_vector(features, "l16_response_mean", safe_mean(zone_tokens(hidden, 16, zones["response"])))\n    last_response_pos = int(zones["response"][-1].item())\n    add_vector(features, "l16_response_last_token", layer_vector(hidden, 16, last_response_pos))\n    add_vector(features, "l16_response_last5_mean", safe_mean(zone_tokens(hidden, 16, zones["response_last5"])))\n\n\n# ============================================================\n# 4. EXACT COMPACT GEOMETRY L10-L19\n# ============================================================\n\n\ndef add_exact_compact_geometry_l10_l19(\n    features: Dict[str, float],\n    hidden: torch.Tensor,\n    zones: Dict[str, torch.Tensor],\n) -> None:\n    response_idx = zones["response_wo_eos"]\n    last_response_pos = int(response_idx[-1].item())\n\n    response_means: Dict[int, torch.Tensor] = {}\n    last_vectors: Dict[int, torch.Tensor] = {}\n    l2_mean_values = []\n    l2_std_values = []\n    l2_max_values = []\n    cos_values = []\n    l2_between_values = []\n    norm_drift_values = []\n    mean_cos_values = []\n    mean_l2_values = []\n\n    for layer in COMPACT_LAYERS:\n        tokens = zone_tokens(hidden, layer, response_idx)\n        norms = torch.linalg.norm(tokens.float(), dim=1).detach().cpu().numpy()\n        response_means[layer] = safe_mean(tokens)\n        last_vectors[layer] = layer_vector(hidden, layer, last_response_pos)\n\n        add_scalar(features, f"response_l2_mean_l{layer}", norms.mean() if norms.size else 0.0)\n        add_scalar(features, f"response_l2_std_l{layer}", norms.std() if norms.size else 0.0)\n        add_scalar(features, f"response_l2_max_l{layer}", norms.max() if norms.size else 0.0)\n\n        l2_mean_values.append(clean_value(norms.mean() if norms.size else 0.0))\n        l2_std_values.append(clean_value(norms.std() if norms.size else 0.0))\n        l2_max_values.append(clean_value(norms.max() if norms.size else 0.0))\n\n    for left, right in zip(COMPACT_LAYERS[:-1], COMPACT_LAYERS[1:]):\n        left_last = last_vectors[left]\n        right_last = last_vectors[right]\n        left_mean = response_means[left]\n        right_mean = response_means[right]\n\n        cos_lr = safe_cosine(left_last, right_last)\n        l2_lr = safe_l2(right_last - left_last)\n        norm_drift = abs(safe_l2(right_last) - safe_l2(left_last))\n        mean_cos = safe_cosine(left_mean, right_mean)\n        mean_l2 = safe_l2(right_mean - left_mean)\n\n        pair = f"l{left}_to_l{right}"\n        add_scalar(features, f"last_response_token_cos_{pair}", cos_lr)\n        add_scalar(features, f"last_response_token_l2_{pair}", l2_lr)\n        add_scalar(features, f"abs_norm_drift_{pair}", norm_drift)\n        add_scalar(features, f"response_mean_cos_{pair}", mean_cos)\n        add_scalar(features, f"response_mean_l2_{pair}", mean_l2)\n\n        cos_values.append(cos_lr)\n        l2_between_values.append(l2_lr)\n        norm_drift_values.append(norm_drift)\n        mean_cos_values.append(mean_cos)\n        mean_l2_values.append(mean_l2)\n\n    add_basic_stats(features, "compact_response_l2_mean_per_layer", l2_mean_values)\n    add_basic_stats(features, "compact_response_l2_std_per_layer", l2_std_values)\n    add_basic_stats(features, "compact_response_l2_max_per_layer", l2_max_values)\n    add_basic_stats(features, "compact_last_response_token_cos_between_layers", cos_values)\n    add_basic_stats(features, "compact_last_response_token_l2_between_layers", l2_between_values)\n    add_basic_stats(features, "compact_abs_norm_drift_between_layers", norm_drift_values)\n    add_basic_stats(features, "compact_response_mean_cos_between_layers", mean_cos_values)\n    add_basic_stats(features, "compact_response_mean_l2_between_layers", mean_l2_values)\n\n    add_scalar(features, "response_fraction", zones["response"].numel() / (zones["all"].numel() + EPS))\n    add_scalar(features, "log_response_len", np.log1p(zones["response"].numel()))\n\n\n# ============================================================\n# 5. EXACT SGI\n# ============================================================\n\n\ndef add_exact_sgi_features(\n    features: Dict[str, float],\n    hidden: torch.Tensor,\n    zones: Dict[str, torch.Tensor],\n) -> None:\n    sgi_values = []\n    last_response_pos = int(zones["response_wo_eos"][-1].item())\n    embedding_ref = safe_mean(zone_tokens(hidden, 0, zones["all"]))\n\n    for layer in COMPACT_LAYERS:\n        prompt_center = safe_mean(zone_tokens(hidden, layer, zones["prompt"]))\n        response_last = layer_vector(hidden, layer, last_response_pos)\n\n        angle_to_prompt = safe_angle(response_last, prompt_center)\n        angle_to_embedding = safe_angle(response_last, embedding_ref)\n        sgi = angle_to_prompt / (angle_to_embedding + EPS)\n\n        add_scalar(features, f"sgi_l{layer}", sgi)\n        sgi_values.append(sgi)\n\n    add_scalar(features, "sgi_mean", np.mean(sgi_values))\n    add_scalar(features, "sgi_std", np.std(sgi_values))\n    add_scalar(features, "sgi_min", np.min(sgi_values))\n    add_scalar(features, "sgi_max", np.max(sgi_values))\n    add_scalar(features, "sgi_late_minus_early", np.mean(sgi_values[-3:]) - np.mean(sgi_values[:3]))\n\n\n# ============================================================\n# 6. EXACT PROMPT-RESPONSE CENTROID SIMILARITY\n# ============================================================\n\n\ndef add_exact_centroid_features(\n    features: Dict[str, float],\n    hidden: torch.Tensor,\n    zones: Dict[str, torch.Tensor],\n) -> None:\n    cos_values = []\n    l2_values = []\n    norm_ratio_values = []\n\n    for layer in CENTROID_LAYERS:\n        prompt_center = safe_mean(zone_tokens(hidden, layer, zones["prompt"]))\n        response_center = safe_mean(zone_tokens(hidden, layer, zones["response_wo_eos"]))\n\n        cos = safe_cosine(prompt_center, response_center)\n        l2 = safe_l2(response_center - prompt_center)\n        angle = safe_angle(prompt_center, response_center)\n        norm_ratio = safe_l2(response_center) / (safe_l2(prompt_center) + EPS)\n        drift = l2\n\n        add_scalar(features, f"centroid_cos_l{layer}", cos)\n        add_scalar(features, f"centroid_l2_l{layer}", l2)\n        add_scalar(features, f"centroid_angle_l{layer}", angle)\n        add_scalar(features, f"centroid_norm_ratio_l{layer}", norm_ratio)\n        add_scalar(features, f"centroid_drift_l{layer}", drift)\n\n        cos_values.append(cos)\n        l2_values.append(l2)\n        norm_ratio_values.append(norm_ratio)\n\n    add_basic_stats(features, "centroid_cos", cos_values)\n    add_basic_stats(features, "centroid_l2", l2_values)\n    add_basic_stats(features, "centroid_norm_ratio", norm_ratio_values)\n\n\n# ============================================================\n# 7. EXACT RESPONSE TEMPORAL DYNAMICS\n# ============================================================\n\n\ndef add_temporal_dynamics_for_tokens(\n    features: Dict[str, float],\n    prefix: str,\n    tokens: torch.Tensor,\n) -> None:\n    arr = to_numpy(tokens)\n    if arr.ndim != 2 or arr.shape[0] < 2:\n        for name in [\n            "velocity_norm_mean", "velocity_norm_std", "velocity_norm_max",\n            "acceleration_norm_mean", "acceleration_norm_std", "acceleration_norm_max",\n            "curvature_cos_mean", "curvature_cos_std", "curvature_cos_min",\n            "direction_reversal_rate", "path_length", "endpoint_distance",\n            "path_efficiency", "trajectory_roughness", "late_velocity_spike_ratio",\n        ]:\n            add_scalar(features, f"{prefix}_{name}", 0.0)\n        return\n\n    velocity = np.diff(arr, axis=0)\n    velocity_norms = np.linalg.norm(velocity, axis=1)\n\n    if velocity.shape[0] >= 2:\n        acceleration = np.diff(velocity, axis=0)\n        v1 = velocity[:-1]\n        v2 = velocity[1:]\n        denom = np.linalg.norm(v1, axis=1) * np.linalg.norm(v2, axis=1) + EPS\n        curvature_cos = np.sum(v1 * v2, axis=1) / denom\n    else:\n        acceleration = np.zeros((1, arr.shape[1]), dtype=np.float32)\n        curvature_cos = np.array([1.0], dtype=np.float32)\n\n    acceleration_norms = np.linalg.norm(acceleration, axis=1)\n    path_length = clean_value(velocity_norms.sum())\n    endpoint_distance = clean_value(np.linalg.norm(arr[-1] - arr[0]))\n    split = max(1, len(velocity_norms) // 2)\n    early_vel = velocity_norms[:split].mean()\n    late_vel = velocity_norms[split:].mean() if split < len(velocity_norms) else velocity_norms[-1]\n\n    add_scalar(features, f"{prefix}_velocity_norm_mean", velocity_norms.mean())\n    add_scalar(features, f"{prefix}_velocity_norm_std", velocity_norms.std())\n    add_scalar(features, f"{prefix}_velocity_norm_max", velocity_norms.max())\n    add_scalar(features, f"{prefix}_acceleration_norm_mean", acceleration_norms.mean())\n    add_scalar(features, f"{prefix}_acceleration_norm_std", acceleration_norms.std())\n    add_scalar(features, f"{prefix}_acceleration_norm_max", acceleration_norms.max())\n    add_scalar(features, f"{prefix}_curvature_cos_mean", curvature_cos.mean())\n    add_scalar(features, f"{prefix}_curvature_cos_std", curvature_cos.std())\n    add_scalar(features, f"{prefix}_curvature_cos_min", curvature_cos.min())\n    add_scalar(features, f"{prefix}_direction_reversal_rate", np.mean(curvature_cos < 0.0))\n    add_scalar(features, f"{prefix}_path_length", path_length)\n    add_scalar(features, f"{prefix}_endpoint_distance", endpoint_distance)\n    add_scalar(features, f"{prefix}_path_efficiency", endpoint_distance / (path_length + EPS))\n    add_scalar(features, f"{prefix}_trajectory_roughness", acceleration_norms.sum() / (path_length + EPS))\n    add_scalar(features, f"{prefix}_late_velocity_spike_ratio", late_vel / (early_vel + EPS))\n\n\ndef add_exact_temporal_dynamics(\n    features: Dict[str, float],\n    hidden: torch.Tensor,\n    zones: Dict[str, torch.Tensor],\n) -> None:\n    for layer in TEMPORAL_LAYERS:\n        for zone_name in ["response_wo_eos", "response_late30", "response_last10"]:\n            tokens = zone_tokens(hidden, layer, zones[zone_name])\n            add_temporal_dynamics_for_tokens(features, f"temporal_l{layer}_{zone_name}", tokens)\n\n\n# ============================================================\n# 8. EXACT CROSS-LAYER UPDATE NORMS\n# ============================================================\n\n\ndef add_exact_cross_layer_update_features(\n    features: Dict[str, float],\n    hidden: torch.Tensor,\n    zones: Dict[str, torch.Tensor],\n) -> None:\n    for zone_name in ["response_wo_eos", "response_last10", "response_last5"]:\n        all_mean_norms = []\n        all_std_norms = []\n        all_max_norms = []\n        all_min_norms = []\n        all_cv_norms = []\n        all_cos_consistency = []\n        all_anisotropy = []\n        previous_mean_update = None\n\n        for left, right in zip(COMPACT_LAYERS[:-1], COMPACT_LAYERS[1:]):\n            left_tokens = zone_tokens(hidden, left, zones[zone_name])\n            right_tokens = zone_tokens(hidden, right, zones[zone_name])\n            min_len = min(left_tokens.shape[0], right_tokens.shape[0])\n            update = right_tokens[:min_len] - left_tokens[:min_len]\n            norms = torch.linalg.norm(update.float(), dim=1).detach().cpu().numpy()\n            mean_update = safe_mean(update)\n\n            mean_norm = clean_value(norms.mean() if norms.size else 0.0)\n            std_norm = clean_value(norms.std() if norms.size else 0.0)\n            max_norm = clean_value(norms.max() if norms.size else 0.0)\n            min_norm = clean_value(norms.min() if norms.size else 0.0)\n            cv_norm = clean_value(std_norm / (mean_norm + EPS))\n            anisotropy = clean_value(max_norm / (mean_norm + EPS))\n            cos_consistency = 1.0 if previous_mean_update is None else safe_cosine(mean_update, previous_mean_update)\n\n            pair = f"l{left}_to_l{right}"\n            prefix = f"cross_update_{zone_name}_{pair}"\n            add_scalar(features, f"{prefix}_update_norm_mean", mean_norm)\n            add_scalar(features, f"{prefix}_update_norm_std", std_norm)\n            add_scalar(features, f"{prefix}_update_norm_max", max_norm)\n            add_scalar(features, f"{prefix}_update_norm_min", min_norm)\n            add_scalar(features, f"{prefix}_update_norm_cv", cv_norm)\n            add_scalar(features, f"{prefix}_update_cosine_consistency", cos_consistency)\n            add_scalar(features, f"{prefix}_update_anisotropy", anisotropy)\n\n            all_mean_norms.append(mean_norm)\n            all_std_norms.append(std_norm)\n            all_max_norms.append(max_norm)\n            all_min_norms.append(min_norm)\n            all_cv_norms.append(cv_norm)\n            all_cos_consistency.append(cos_consistency)\n            all_anisotropy.append(anisotropy)\n            previous_mean_update = mean_update\n\n        add_basic_stats(features, f"cross_update_{zone_name}_update_norm_mean", all_mean_norms)\n        add_basic_stats(features, f"cross_update_{zone_name}_update_norm_std", all_std_norms)\n        add_basic_stats(features, f"cross_update_{zone_name}_update_norm_max", all_max_norms)\n        add_basic_stats(features, f"cross_update_{zone_name}_update_norm_min", all_min_norms)\n        add_basic_stats(features, f"cross_update_{zone_name}_update_norm_cv", all_cv_norms)\n        add_basic_stats(features, f"cross_update_{zone_name}_update_cosine_consistency", all_cos_consistency)\n        add_basic_stats(features, f"cross_update_{zone_name}_update_anisotropy", all_anisotropy)\n        add_scalar(\n            features,\n            f"cross_update_{zone_name}_update_late_minus_early",\n            np.mean(all_mean_norms[-3:]) - np.mean(all_mean_norms[:3]),\n        )\n\n\n# ============================================================\n# 9. EXACT ICR-LITE\n# ============================================================\n\n\ndef spectral_entropy_from_eigvals(eigvals: np.ndarray) -> float:\n    eigvals = np.maximum(np.asarray(eigvals, dtype=np.float64), 0.0)\n    total = eigvals.sum()\n    if total <= EPS:\n        return 0.0\n    probs = eigvals / total\n    return clean_value(-(probs * np.log(probs + EPS)).sum())\n\n\ndef eigvals_from_token_matrix(tokens: torch.Tensor) -> np.ndarray:\n    arr = to_numpy(tokens)\n    if arr.ndim != 2 or arr.shape[0] <= 1:\n        return np.array([0.0], dtype=np.float32)\n    arr = arr - arr.mean(axis=0, keepdims=True)\n    try:\n        singular_values = np.linalg.svd(arr, full_matrices=False, compute_uv=False)\n        eigvals = (singular_values ** 2) / max(arr.shape[0] - 1, 1)\n    except np.linalg.LinAlgError:\n        eigvals = np.array([0.0], dtype=np.float32)\n    eigvals = np.nan_to_num(eigvals, nan=0.0, posinf=0.0, neginf=0.0)\n    return np.maximum(eigvals.astype(np.float32), 0.0)\n\n\ndef add_exact_icr_lite_features(\n    features: Dict[str, float],\n    hidden: torch.Tensor,\n    zones: Dict[str, torch.Tensor],\n) -> None:\n    for layer in ICR_LAYERS:\n        for zone_name in ["prompt", "response_wo_eos", "response_last10"]:\n            tokens = zone_tokens(hidden, layer, zones[zone_name])\n            eigvals = eigvals_from_token_matrix(tokens)\n            total = eigvals.sum()\n            sq_sum = np.square(eigvals).sum()\n            sorted_eigs = np.sort(eigvals)[::-1]\n            positive = sorted_eigs[sorted_eigs > EPS]\n\n            participation_ratio = (total ** 2) / (sq_sum + EPS)\n            top1_ratio = sorted_eigs[0] / (total + EPS) if sorted_eigs.size else 0.0\n            top3_ratio = sorted_eigs[:3].sum() / (total + EPS) if sorted_eigs.size else 0.0\n            entropy = spectral_entropy_from_eigvals(sorted_eigs)\n            effective_rank = math.exp(entropy) if entropy > 0 else 0.0\n            condition_proxy = (positive[0] / (positive[-1] + EPS)) if positive.size >= 2 else 0.0\n\n            prefix = f"icr_l{layer}_{zone_name}"\n            add_scalar(features, f"{prefix}_participation_ratio", participation_ratio)\n            add_scalar(features, f"{prefix}_top1_ratio", top1_ratio)\n            add_scalar(features, f"{prefix}_top3_ratio", top3_ratio)\n            add_scalar(features, f"{prefix}_spectral_entropy", entropy)\n            add_scalar(features, f"{prefix}_effective_rank", effective_rank)\n            add_scalar(features, f"{prefix}_condition_proxy", condition_proxy)\n\n\n# ============================================================\n# SAMPLE EXTRACTION\n# ============================================================\n\n\ndef extract_features_one_sample(\n    hidden: torch.Tensor,\n    valid_mask: torch.Tensor,\n    prompt_len: int,\n) -> Dict[str, float]:\n    hidden = hidden.float().cpu()\n    valid_mask = valid_mask.bool().cpu()\n    zones = build_exact_zones(valid_mask, prompt_len)\n\n    features: Dict[str, float] = {}\n    add_length_meta_features(features, zones, prompt_len, MAX_LENGTH)\n    add_exact_pooling_features(features, hidden, zones)\n    add_exact_compact_geometry_l10_l19(features, hidden, zones)\n    add_exact_sgi_features(features, hidden, zones)\n    add_exact_centroid_features(features, hidden, zones)\n    add_exact_temporal_dynamics(features, hidden, zones)\n    add_exact_cross_layer_update_features(features, hidden, zones)\n    add_exact_icr_lite_features(features, hidden, zones)\n\n    return {key: clean_value(value) for key, value in features.items()}\n\n\n# ============================================================\n# DATASET EXTRACTION\n# ============================================================\n\n\ndef extract_dataset_features(\n    df: pd.DataFrame,\n    model,\n    tokenizer,\n    device: torch.device,\n    has_label: bool,\n) -> pd.DataFrame:\n    prompts = df["prompt"].astype(str).tolist()\n    responses = df["response"].astype(str).tolist()\n    prompt_lengths = get_prompt_len_column_or_tokenize(df, tokenizer)\n    texts = [p + r for p, r in zip(prompts, responses)]\n\n    rows: List[Dict[str, float]] = []\n\n    for start in tqdm(range(0, len(texts), BATCH_SIZE), desc="Extract prompt-len advanced features"):\n        batch_texts = texts[start:start + BATCH_SIZE]\n        batch_prompt_lengths = prompt_lengths[start:start + BATCH_SIZE]\n\n        encoding = tokenizer(\n            batch_texts,\n            return_tensors="pt",\n            padding=True,\n            truncation=True,\n            max_length=MAX_LENGTH,\n        )\n\n        input_ids = encoding["input_ids"].to(device)\n        attention_mask = encoding["attention_mask"].to(device)\n\n        with torch.no_grad():\n            outputs = model(\n                input_ids=input_ids,\n                attention_mask=attention_mask,\n                output_hidden_states=True,\n            )\n\n        hidden_batch = torch.stack(outputs.hidden_states, dim=1).float().cpu()\n        mask_batch = attention_mask.cpu().bool()\n\n        for i in range(hidden_batch.shape[0]):\n            rows.append(\n                extract_features_one_sample(\n                    hidden=hidden_batch[i],\n                    valid_mask=mask_batch[i],\n                    prompt_len=batch_prompt_lengths[i],\n                )\n            )\n\n        del outputs, hidden_batch, mask_batch, input_ids, attention_mask, encoding\n        if torch.cuda.is_available():\n            torch.cuda.empty_cache()\n\n    out = pd.DataFrame(rows)\n    out = out.replace([np.inf, -np.inf], 0.0).fillna(0.0)\n    out.insert(0, "source_index", df.index.to_numpy())\n\n    if has_label:\n        out["label"] = df["label"].astype(float).astype(int).to_numpy()\n\n    out["prompt"] = df["prompt"].astype(str).to_numpy()\n    out["response"] = df["response"].astype(str).to_numpy()\n    return out\n\n\n# ============================================================\n# MAIN\n# ============================================================\n\n\ndef main() -> None:\n    t0 = time.time()\n    device = get_device()\n\n    print("=" * 80)\n    print("BUILD ADVANCED PROMPT-LENGTH-AWARE FEATURES")\n    print("=" * 80)\n    print(f"Device      : {device}")\n    print(f"Data file   : {DATA_FILE}")\n    print(f"Test file   : {TEST_FILE}")\n    print(f"Output dir  : {OUTPUT_DIR}")\n    print(f"Batch size  : {BATCH_SIZE}")\n    print("Note        : uses prompt_len only; no logits, hooks, or attentions")\n\n    model, tokenizer = get_model_and_tokenizer()\n    if tokenizer.pad_token is None:\n        tokenizer.pad_token = tokenizer.eos_token\n\n    model.to(device)\n    model.eval()\n\n    train_df = pd.read_csv(DATA_FILE)\n    print(f"\\nDataset rows: {len(train_df)}")\n    train_features = extract_dataset_features(\n        df=train_df,\n        model=model,\n        tokenizer=tokenizer,\n        device=device,\n        has_label=True,\n    )\n    train_features.to_parquet(TRAIN_OUTPUT, index=False)\n    print(f"Saved train: {TRAIN_OUTPUT}")\n    print(f"Train shape: {train_features.shape}")\n\n    if EXPORT_TEST and Path(TEST_FILE).exists():\n        test_df = pd.read_csv(TEST_FILE)\n        print(f"\\nTest rows: {len(test_df)}")\n        test_features = extract_dataset_features(\n            df=test_df,\n            model=model,\n            tokenizer=tokenizer,\n            device=device,\n            has_label=False,\n        )\n        test_features.to_parquet(TEST_OUTPUT, index=False)\n        print(f"Saved test: {TEST_OUTPUT}")\n        print(f"Test shape: {test_features.shape}")\n\n    print(f"\\nDone in {time.time() - t0:.1f} sec")\n    print("=" * 80)\n\n\nif __name__ == "__main__":\n    main()\n'


def _load_namespace(source: str, name: str) -> dict:
    ns = {"__name__": name}
    exec(compile(source, f"<{name}>", "exec"), ns)
    return ns


_EXTRA_NS = _load_namespace(_EXTRA_SOURCE, "_trackc_extra_smart_prompt_len")
_ATTN_NS = _load_namespace(_ATTN_SOURCE, "_trackc_attention_features")
_ADV_NS = _load_namespace(_ADV_SOURCE, "_trackc_advanced_prompt_len")


# ---------------------------------------------------------------------
# Numerical-safety patch
# ---------------------------------------------------------------------
def _as_finite_np(x, dtype=np.float64, clip=1e6):
    if isinstance(x, torch.Tensor):
        x = x.detach().cpu().float().numpy()
    arr = np.asarray(x, dtype=dtype)
    arr = np.nan_to_num(arr, nan=0.0, posinf=clip, neginf=-clip)
    return np.clip(arr, -clip, clip)


def _safe_covariance_stats(tokens: torch.Tensor) -> dict[str, float]:
    arr = _as_finite_np(tokens, dtype=np.float64, clip=1e6)
    if arr.ndim != 2 or arr.shape[0] <= 2:
        return {
            "trace": 0.0,
            "top1_ratio": 0.0,
            "top3_ratio": 0.0,
            "top5_ratio": 0.0,
            "effective_rank": 0.0,
            "participation_ratio": 0.0,
            "spectral_entropy": 0.0,
        }

    centered = arr - arr.mean(axis=0, keepdims=True)
    centered = np.nan_to_num(centered, nan=0.0, posinf=1e6, neginf=-1e6)
    centered = np.clip(centered, -1e6, 1e6)

    try:
        singular_values = np.linalg.svd(centered, full_matrices=False, compute_uv=False)
    except np.linalg.LinAlgError:
        # Deterministic fallback: use covariance eigenvalues. If that also fails,
        # return zeros instead of crashing the whole official run.
        try:
            cov = centered @ centered.T
            eig = np.linalg.eigvalsh(cov)
            singular_values = np.sqrt(np.maximum(eig, 0.0))
        except Exception:
            singular_values = np.array([0.0], dtype=np.float64)

    eig = np.nan_to_num(singular_values ** 2, nan=0.0, posinf=0.0, neginf=0.0)
    eig = np.maximum(eig, 0.0)
    total = float(eig.sum()) + 1e-8
    if not np.isfinite(total) or total <= 1e-8:
        return {
            "trace": 0.0,
            "top1_ratio": 0.0,
            "top3_ratio": 0.0,
            "top5_ratio": 0.0,
            "effective_rank": 0.0,
            "participation_ratio": 0.0,
            "spectral_entropy": 0.0,
        }

    p = eig / total
    ent = float(-(p * np.log(p + 1e-8)).sum())
    return {
        "trace": _clean_float(total),
        "top1_ratio": _clean_float(p[:1].sum()),
        "top3_ratio": _clean_float(p[:3].sum()),
        "top5_ratio": _clean_float(p[:5].sum()),
        "effective_rank": _clean_float(np.exp(ent)),
        "participation_ratio": _clean_float((eig.sum() ** 2) / ((eig ** 2).sum() + 1e-8)),
        "spectral_entropy": _clean_float(ent),
    }


def _safe_pairwise_cosine_stats(tokens: torch.Tensor) -> dict[str, float]:
    arr = _as_finite_np(tokens, dtype=np.float64, clip=1e6)
    if arr.ndim != 2 or arr.shape[0] <= 1:
        return {"mean": 1.0, "std": 0.0, "min": 1.0, "p10": 1.0, "p90": 1.0}

    norms = np.linalg.norm(arr, axis=1, keepdims=True)
    arr = arr / (norms + 1e-8)
    arr = np.nan_to_num(arr, nan=0.0, posinf=0.0, neginf=0.0)
    sim = arr @ arr.T
    tri = sim[np.triu_indices_from(sim, k=1)]
    tri = np.nan_to_num(tri, nan=0.0, posinf=0.0, neginf=0.0)
    if tri.size == 0:
        tri = np.array([1.0], dtype=np.float64)
    return {
        "mean": _clean_float(tri.mean()),
        "std": _clean_float(tri.std()),
        "min": _clean_float(tri.min()),
        "p10": _clean_float(np.percentile(tri, 10)),
        "p90": _clean_float(np.percentile(tri, 90)),
    }


# The original notebook scripts assumed numerically clean hidden states. In the
# official online pipeline, especially on MPS, rare samples can produce inf/nan
# values and make SVD fail. Override the fragile helper functions in the embedded
# namespaces without changing feature names or dimensionality.
_EXTRA_NS["covariance_stats"] = _safe_covariance_stats
_EXTRA_NS["pairwise_cosine_stats"] = _safe_pairwise_cosine_stats



def _clean_float(value) -> float:
    try:
        value = float(value)
    except Exception:
        return 0.0
    if not np.isfinite(value):
        return 0.0
    return value


def _values_in_order(features: dict, view_key: str) -> list[float]:
    return [_clean_float(features.get(col, 0.0)) for col in _SELECTED_BY_KEY[view_key]["selected_cols"]]


def _fallback_prompt_len(attention_mask: torch.Tensor) -> int:
    # This is only a safety fallback. For the real Track C solution, solution.py
    # must pass exact prompt_len computed by tokenizing the prompt only.
    return int(attention_mask.bool().sum().item())


def aggregate(
    hidden_states: torch.Tensor,
    attention_mask: torch.Tensor,
    prompt_len: int | None = None,
    attentions: Sequence[torch.Tensor] | None = None,
) -> torch.Tensor:
    """Return exactly 2432 Track C selected raw features for one sample."""
    prompt_len = _fallback_prompt_len(attention_mask) if prompt_len is None else int(prompt_len)

    hidden_cpu = torch.nan_to_num(hidden_states.detach().float().cpu(), nan=0.0, posinf=1e6, neginf=-1e6).clamp(-1e6, 1e6)
    mask_cpu = attention_mask.detach().bool().cpu()

    extra_features = _EXTRA_NS["extract_features_one_sample"](
        hidden=hidden_cpu,
        valid_mask=mask_cpu,
        prompt_len=prompt_len,
    )
    adv_features = _ADV_NS["extract_features_one_sample"](
        hidden=hidden_cpu,
        valid_mask=mask_cpu,
        prompt_len=prompt_len,
    )

    if attentions is None:
        # Keep dimensionality stable if someone runs the old solution.py.
        # The intended official pipeline should pass attentions; otherwise the
        # two attention views will be zeros and quality will drop.
        attn_features = {}
    else:
        attn_cpu = [a.detach().float().cpu() for a in attentions]
        attn_features = _ATTN_NS["extract_features_one_sample"](
            attentions=attn_cpu,
            valid_mask=mask_cpu,
            prompt_len=prompt_len,
        )

    values = []
    values.extend(_values_in_order(extra_features, "B__extra_smart_prompt_len_all__top312_pca64"))
    values.extend(_values_in_order(attn_features, "C__attention_all__top866_pca64"))
    values.extend(_values_in_order(adv_features, "B__advanced_prompt_len_max_mean__top1250_pca128"))
    values.extend(_values_in_order(attn_features, "C__attention_sink__selected4"))

    return torch.tensor(values, dtype=torch.float32)


def extract_geometric_features(
    hidden_states: torch.Tensor,
    attention_mask: torch.Tensor,
    prompt_len: int | None = None,
    attentions: Sequence[torch.Tensor] | None = None,
) -> torch.Tensor:
    # All selected Track C features are returned by aggregate(); keep this empty
    # for compatibility with the official skeleton.
    return torch.zeros(0, dtype=torch.float32)


def aggregation_and_feature_extraction(
    hidden_states: torch.Tensor,
    attention_mask: torch.Tensor,
    use_geometric: bool = False,
    prompt_len: int | None = None,
    attentions: Sequence[torch.Tensor] | None = None,
) -> torch.Tensor:
    # use_geometric is intentionally ignored: the selected 2432 features are the
    # full feature vector for this solution.
    return aggregate(
        hidden_states=hidden_states,
        attention_mask=attention_mask,
        prompt_len=prompt_len,
        attentions=attentions,
    )
